import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TreeItem {
  id: string;
  qty: number;
  type: string;
  diameter: number;
}

export enum TreeSize {
  SMALL = 'Small (4m)',
  MEDIUM = 'Medium (6m)',
  LARGE = 'Large (8m+)'
}

export interface SoilEntry {
  id: string;
  areaId: string;
  treeSize: TreeSize;
  soilAreaProvided: number;
  isCluster: boolean;
}

export interface AnalysisResponse {
  summary: string;
  recommendations: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { TreeItem, SoilEntry } from "../types";

export const getAIPlanningInsights = async (
  siteArea: number,
  targetPct: number,
  trees: TreeItem[],
  soilEntries: SoilEntry[]
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    As an Urban Landscape Architect, analyze this site:
    Total Site Area: ${siteArea} m2
    Target Canopy Percentage: ${targetPct}%
    Current Trees: ${JSON.stringify(trees)}
    Soil Provisions: ${JSON.stringify(soilEntries)}

    Provide a concise professional summary and 3-4 actionable recommendations to improve canopy health or meet urban planning targets.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          recommendations: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "recommendations"]
      }
    }
  });

  return JSON.parse(response.text);
};

import React, { useState } from 'react';
