export default App;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Plus, Trash2, TreePine, AlertCircle, CheckCircle2 } from 'lucide-react';
import { TreeItem } from '../types';

interface Props {
  siteArea: number;
  setSiteArea: (v: number) => void;
  targetPct: number;
  setTargetPct: (v: number) => void;
  trees: TreeItem[];
  setTrees: (v: TreeItem[]) => void;
}

export const CanopyCalculator: React.FC<Props> = ({ siteArea, setSiteArea, targetPct, setTargetPct, trees, setTrees }) => {
  const calculateArea = (dia: number) => Math.PI * Math.pow(dia / 2, 2);
  const totalCanopy = trees.reduce((acc, t) => acc + (calculateArea(t.diameter) * t.qty), 0);
  const minRequired = siteArea * (targetPct / 100);
  const diff = totalCanopy - minRequired;
  const currentPct = (totalCanopy / siteArea) * 100;

  const chartData = [
    { name: 'Current Canopy', value: totalCanopy, color: '#10b981' },
    { name: 'Remaining Area', value: Math.max(0, siteArea - totalCanopy), color: '#e2e8f0' }
  ];

  const addTree = () => {
    const id = Math.random().toString(36).substr(2, 9);
    setTrees([...trees, { id, qty: 1, type: 'New Tree', diameter: 5.0 }]);
  };

  const removeTree = (id: string) => {
    setTrees(trees.filter(t => t.id !== id));
  };

  const updateTree = (id: string, updates: Partial<TreeItem>) => {
    setTrees(trees.map(t => t.id === id ? { ...t, ...updates } : t));
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Configuration Panel */}
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-emerald-100 p-1.5 rounded-md"><TreePine size={18} className="text-emerald-600" /></div>
            Site Parameters
          </h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Total Site Area (m²)</label>
              <input 
                type="number" 
                value={siteArea}
                onChange={(e) => setSiteArea(Number(e.target.value))}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-all outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1 flex justify-between">
                Target Coverage <span>{targetPct}%</span>
              </label>
              <input 
                type="range" 
                min="0" max="100" 
                value={targetPct}
                onChange={(e) => setTargetPct(Number(e.target.value))}
                className="w-full accent-emerald-600 cursor-pointer"
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4">Summary Metrics</h2>
          <div className="space-y-4">
            <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
              <span className="text-sm text-slate-500">Min. Required</span>
              <span className="font-bold text-slate-800">{minRequired.toFixed(2)} m²</span>
            </div>
            <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
              <span className="text-sm text-slate-500">Current Total</span>
              <span className="font-bold text-emerald-600">{totalCanopy.toFixed(2)} m²</span>
            </div>

            <div className={`p-4 rounded-xl flex items-center gap-3 ${diff >= 0 ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-rose-50 text-rose-700 border border-rose-100'}`}>
              {diff >= 0 ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
              <div>
                <p className="font-bold text-sm">{diff >= 0 ? 'Target Achieved' : 'Below Target'}</p>
                <p className="text-xs opacity-90">{Math.abs(diff).toFixed(2)} m² {diff >= 0 ? 'excess' : 'shortfall'}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-64 relative">
          <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider text-center mb-2">Coverage Visualizer</h2>
          <ResponsiveContainer width="100%" height="80%">
            <PieChart>
              <Pie
                data={chartData}
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none mt-6">
            <span className="text-2xl font-bold text-slate-800">{currentPct.toFixed(1)}%</span>
            <span className="text-[10px] text-slate-400 font-medium">CURRENT</span>
          </div>
        </div>
      </div>

      {/* Tree Inventory Table */}
      <div className="lg:col-span-2">
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div>
              <h2 className="text-xl font-bold text-slate-800">Proposed Tree Inventory</h2>
              <p className="text-sm text-slate-500">Manage species and dimensions to reach target goals</p>
            </div>
            <button 
              onClick={addTree}
              className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg transition-colors font-medium text-sm shadow-sm"
            >
              <Plus size={18} /> Add Tree
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Quantity</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Description/Type</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Diameter (m)</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider text-right">Total Area (m²)</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {trees.map((tree) => (
                  <tr key={tree.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-6 py-4">
                      <input 
                        type="number" 
                        min="1"
                        value={tree.qty}
                        onChange={(e) => updateTree(tree.id, { qty: Number(e.target.value) })}
                        className="w-20 px-3 py-1.5 rounded border border-slate-200 focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 outline-none text-sm"
                      />
                    </td>
                    <td className="px-6 py-4">
                      <input 
                        type="text" 
                        value={tree.type}
                        onChange={(e) => updateTree(tree.id, { type: e.target.value })}
                        placeholder="e.g. Maple"
                        className="w-full bg-transparent border-b border-transparent hover:border-slate-200 focus:border-emerald-500 py-1 outline-none text-sm transition-all"
                      />
                    </td>
                    <td className="px-6 py-4">
                      <input 
                        type="number" 
                        step="0.5"
                        value={tree.diameter}
                        onChange={(e) => updateTree(tree.id, { diameter: Number(e.target.value) })}
                        className="w-20 px-3 py-1.5 rounded border border-slate-200 focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 outline-none text-sm"
                      />
                    </td>
                    <td className="px-6 py-4 text-right font-medium text-slate-700">
                      {(calculateArea(tree.diameter) * tree.qty).toFixed(2)}
                    </td>
                    <td className="px-6 py-4">
                      <button 
                        onClick={() => removeTree(tree.id)}
                        className="text-slate-300 hover:text-rose-500 transition-colors"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
              {trees.length === 0 && (
                <tbody>
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-400 italic">
                      No trees added to the inventory yet.
                    </td>
                  </tr>
                </tbody>
              )}
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Plus, Trash2, Shovel, Info, CheckCircle2, XCircle } from 'lucide-react';
import { SoilEntry, TreeSize } from '../types';

interface Props {
  entries: SoilEntry[];
  setEntries: (v: SoilEntry[]) => void;
}

export const DeepSoilCalculator: React.FC<Props> = ({ entries, setEntries }) => {
  const addEntry = () => {
    const id = Math.random().toString(36).substr(2, 9);
    setEntries([...entries, { 
      id, 
      areaId: `Area ${entries.length + 1}`, 
      treeSize: TreeSize.MEDIUM, 
      soilAreaProvided: 25.0, 
      isCluster: false 
    }]);
  };

  const removeEntry = (id: string) => {
    setEntries(entries.filter(e => e.id !== id));
  };

  const updateEntry = (id: string, updates: Partial<SoilEntry>) => {
    setEntries(entries.map(e => e.id === id ? { ...e, ...updates } : e));
  };

  const getRequirements = (entry: SoilEntry) => {
    let base = 0;
    switch (entry.treeSize) {
      case TreeSize.SMALL: base = 12; break;
      case TreeSize.MEDIUM: base = 25; break;
      case TreeSize.LARGE: base = 60; break;
    }
    const reduction = entry.isCluster ? 0.95 : 1.0;
    return base * reduction;
  };

  return (
    <div className="space-y-6">
      <div className="bg-emerald-900 text-white p-8 rounded-3xl relative overflow-hidden">
        <div className="relative z-10">
          <h2 className="text-2xl font-bold mb-2 flex items-center gap-2">
            <Shovel size={28} /> Deep Soil Volume Assessment
          </h2>
          <p className="text-emerald-100/80 max-w-2xl mb-4">
            Ensuring adequate root volume is critical for tree longevity. Standards require at least 0.6m³ of soil per 1m² of canopy projection area.
          </p>
          <div className="flex gap-4">
            <div className="bg-emerald-800/50 px-4 py-2 rounded-lg text-sm border border-emerald-700/50 backdrop-blur-sm">
              <span className="font-semibold text-emerald-300">Small:</span> 12m² Area
            </div>
            <div className="bg-emerald-800/50 px-4 py-2 rounded-lg text-sm border border-emerald-700/50 backdrop-blur-sm">
              <span className="font-semibold text-emerald-300">Medium:</span> 25m² Area
            </div>
            <div className="bg-emerald-800/50 px-4 py-2 rounded-lg text-sm border border-emerald-700/50 backdrop-blur-sm">
              <span className="font-semibold text-emerald-300">Large:</span> 60m² Area
            </div>
          </div>
        </div>
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/10 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 flex justify-between items-center border-b border-slate-100">
          <h3 className="font-bold text-slate-800 flex items-center gap-2">
            Soil Allocation Log
            <span className="bg-slate-100 text-slate-500 text-xs px-2 py-0.5 rounded-full">{entries.length} Zones</span>
          </h3>
          <button 
            onClick={addEntry}
            className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2 rounded-xl transition-all shadow-sm font-medium flex items-center gap-2"
          >
            <Plus size={18} /> New Soil Zone
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-slate-50/50">
          {entries.map((entry) => {
            const req = getRequirements(entry);
            const isPass = entry.soilAreaProvided >= req;

            return (
              <div key={entry.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow flex flex-col gap-4 relative">
                <div className="flex justify-between items-start">
                  <input 
                    type="text" 
                    value={entry.areaId}
                    onChange={(e) => updateEntry(entry.id, { areaId: e.target.value })}
                    className="font-bold text-slate-800 border-b border-transparent focus:border-emerald-500 outline-none text-lg w-full mr-8"
                  />
                  <button 
                    onClick={() => removeEntry(entry.id)}
                    className="text-slate-300 hover:text-rose-500 transition-colors absolute top-5 right-5"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>

                <div className="space-y-3">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase mb-1 block">Tree Target Size</label>
                    <select 
                      value={entry.treeSize}
                      onChange={(e) => updateEntry(entry.id, { treeSize: e.target.value as TreeSize })}
                      className="w-full px-3 py-2 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
                    >
                      {Object.values(TreeSize).map(size => (
                        <option key={size} value={size}>{size}</option>
                      ))}
                    </select>
                  </div>

                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase mb-1 block">Provided Area (m²)</label>
                    <input 
                      type="number" 
                      value={entry.soilAreaProvided}
                      onChange={(e) => updateEntry(entry.id, { soilAreaProvided: Number(e.target.value) })}
                      className="w-full px-3 py-2 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
                    />
                  </div>

                  <label className="flex items-center gap-2 cursor-pointer group">
                    <input 
                      type="checkbox" 
                      checked={entry.isCluster}
                      onChange={(e) => updateEntry(entry.id, { isCluster: e.target.checked })}
                      className="w-4 h-4 accent-emerald-600 rounded"
                    />
                    <span className="text-sm text-slate-600 group-hover:text-emerald-700 transition-colors">Shared Cluster (-5% Req)</span>
                  </label>
                </div>

                <div className="mt-2 pt-4 border-t border-slate-100 flex justify-between items-end">
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase leading-none mb-1">Status</p>
                    <div className={`flex items-center gap-1.5 font-bold ${isPass ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {isPass ? <CheckCircle2 size={16} /> : <XCircle size={16} />}
                      {isPass ? 'PASSED' : 'FAILED'}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-bold text-slate-400 uppercase leading-none mb-1">Target</p>
                    <p className="text-sm font-semibold text-slate-700">{req.toFixed(1)} m²</p>
                  </div>
                </div>
              </div>
            );
          })}

          {entries.length === 0 && (
            <div className="col-span-full py-16 flex flex-col items-center text-slate-400">
              <Shovel size={48} className="opacity-10 mb-4" />
              <p className="italic">Click "New Soil Zone" to begin deep soil calculations.</p>
            </div>
          )}
        </div>
      </div>

      <div className="bg-blue-50 border border-blue-100 p-4 rounded-xl flex gap-3 text-blue-800">
        <Info className="flex-shrink-0" size={20} />
        <p className="text-sm">
          <strong>Planning Tip:</strong> Grouping trees in a single soil volume (Clustering) allows roots to share space, increasing biological resilience and reducing the total per-tree footprint by 5-10% in high-density urban environments.
        </p>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BrainCircuit, Sparkles, Loader2, ArrowRight } from 'lucide-react';
import { getAIPlanningInsights } from '../services/geminiService';
import { TreeItem, SoilEntry, AnalysisResponse } from '../types';

interface Props {
  siteArea: number;
  targetPct: number;
  trees: TreeItem[];
  soilEntries: SoilEntry[];
}

export const AIInsights: React.FC<Props> = ({ siteArea, targetPct, trees, soilEntries }) => {
  const [loading, setLoading] = useState(false);
  const [insights, setInsights] = useState<AnalysisResponse | null>(null);
  const [error, setError] = useState<string | null>(null);

  const generateInsights = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await getAIPlanningInsights(siteArea, targetPct, trees, soilEntries);
      setInsights(data);
    } catch (err: any) {
      setError("Unable to generate AI insights. Check your connection or API key.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="text-center space-y-4">
        <div className="bg-indigo-100 text-indigo-700 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto shadow-sm">
          <BrainCircuit size={32} />
        </div>
        <h2 className="text-3xl font-extrabold text-slate-800 tracking-tight">AI Planning Consultant</h2>
        <p className="text-slate-500 max-w-xl mx-auto">
