                  <div className="flex flex-col gap-2">
                    <label className="flex items-center gap-2 cursor-pointer group">
                        <input 
                        type="checkbox" 
                        checked={entry.isCluster}
                        onChange={(e) => updateEntry(entry.id, { isCluster: e.target.checked })}
                        className="w-4 h-4 accent-emerald-600 rounded"
                        />
                        <span className="text-xs text-slate-600 group-hover:text-emerald-700 transition-colors">Shared Cluster (Reduction enabled)</span>
                    </label>
                    <div className="flex items-center gap-1.5 text-[10px] text-slate-400 bg-slate-50 px-2 py-1 rounded italic border border-slate-100">
