                      {isPass ? <CheckCircle2 size={14} /> : <XCircle size={14} />}
                      {isPass ? 'COMPLIANT' : 'SHORTFALL'}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-bold text-slate-400 uppercase leading-none mb-1">Table B Target</p>
                    <p className="text-sm font-bold text-slate-800">{req.toFixed(1)} m²</p>
