          })}

          {entries.length === 0 && (
            <div className="col-span-full py-16 flex flex-col items-center text-slate-400">
              <Shovel size={48} className="opacity-10 mb-4" />
              <p className="italic">Click "New Soil Zone" to begin deep soil calculations.</p>
            </div>
          )}
        </div>
      </div>

      <div className="bg-blue-50 border border-blue-100 p-5 rounded-2xl flex gap-4 text-blue-800">
        <div className="bg-blue-100 p-2 rounded-xl flex-shrink-0 self-start">
            <Info className="text-blue-600" size={24} />
        </div>
        <div className="text-sm space-y-2">
          <p className="font-bold text-base">Planning Requirement: Soil Plan Dimension</p>
          <p className="leading-relaxed">
            While soil volume is critical, roots also need horizontal space for lateral support. <strong>Minimum soil plan dimension</strong> represents the narrowest width of the soil area. If your zone is 1m wide but 100m long, it may meet the volume but fail the structural stability requirement for large canopy trees.
          </p>
        </div>
      </div>
    </div>
  );
};

