            disabled={trees.length === 0}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl transition-all font-bold text-sm shadow-sm ${trees.length === 0 ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-700 text-white'}`}
          >
            <Plus size={18} /> Add Soil Zone
          </button>
        </div>

        {trees.length === 0 ? (
          <div className="p-12 text-center space-y-4">
            <div className="bg-rose-50 text-rose-500 p-4 rounded-full w-16 h-16 flex items-center justify-center mx-auto">
