    if (diameter < 6) return { req: 16, dim: 3.0, class: 'A' };
    if (diameter < 7) return { req: 25, dim: 3.5, class: 'A' };
    if (diameter < 8) return { req: 36, dim: 4.0, class: 'A' };
    if (diameter < 9) return { req: 49, dim: 4.5, class: 'B' };
    if (diameter < 10) return { req: 64, dim: 5.0, class: 'B' };
    if (diameter < 11) return { req: 81, dim: 5.5, class: 'B' };
    if (diameter < 12) return { req: 100, dim: 6.0, class: 'B' };
    if (diameter < 13) return { req: 121, dim: 6.5, class: 'C' };
    if (diameter < 14) return { req: 136, dim: 7.0, class: 'C' };
    return { req: 144, dim: 7.5, class: 'C' };
  };

  const getTreeCode = (tree: TreeItem) => {
    const getClassification = (d: number): 'A' | 'B' | 'C' => {
        if (d >= 12) return 'C';
        if (d >= 8) return 'B';
        return 'A';
    };

    const sameClass = trees
        .filter(t => getClassification(t.diameter) === getClassification(tree.diameter))
        .sort((a,b) => a.diameter - b.diameter);
    const index = sameClass.findIndex(t => t.id === tree.id) + 1;
    return `${getClassification(tree.diameter)}${index.toString().padStart(2, '0')}`;
  };

  return (
    <div className="space-y-6">
      {/* Informational Header */}
      <div className="bg-emerald-900 text-white p-8 rounded-3xl relative overflow-hidden shadow-xl">
        <div className="relative z-10">
          <h2 className="text-2xl font-bold mb-2 flex items-center gap-2">
            <Shovel size={28} /> Deep Soil Volume Assessment
          </h2>
          <p className="text-emerald-100/80 max-w-2xl mb-6">
            Ensuring adequate root volume is critical for tree health. This calculator applies **Table B** standards. For shared zones, requirements for all trees are aggregated.
          </p>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3 max-w-3xl">
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Small (Type A)</p>
                <p className="text-sm font-medium">12m² &ndash; 36m² Area Req.</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Medium (Type B)</p>
                <p className="text-sm font-medium">49m² &ndash; 100m² Area Req.</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Large (Type C)</p>
                <p className="text-sm font-medium">121m² &ndash; 144m² Area Req.</p>
            </div>
          </div>
        </div>
        <div className="absolute top-0 right-0 w-80 h-80 bg-emerald-500/10 rounded-full -translate-y-1/3 translate-x-1/3 blur-3xl"></div>
      </div>

      {/* Calculator Table */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Soil Allocation Log</h3>
            <p className="text-sm text-slate-500 italic">Zones can contain multiple trees from your inventory</p>
          </div>
          <button 
            onClick={addEntry}
            disabled={trees.length === 0}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl transition-all font-bold text-sm shadow-sm ${ trees.length === 0 ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200' : 'bg-emerald-600 hover:bg-emerald-700 text-white'}`}
          >
            <Plus size={18} /> Add Soil Zone
          </button>
        </div>

        {trees.length === 0 ? (
          <div className="p-12 text-center space-y-4">
            <div className="bg-rose-50 text-rose-500 p-4 rounded-full w-16 h-16 flex items-center justify-center mx-auto">
                <AlertCircle size={32} />
            </div>
            <div className="max-w-xs mx-auto">
                <p className="font-bold text-slate-800">No Trees Detected</p>
                <p className="text-sm text-slate-500">Please add trees to your <strong>Proposed Tree Inventory</strong> in the Canopy tab first.</p>
            </div>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-200">
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Zone ID</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Linked Trees</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Provided Soil (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Cluster?</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Agg. Target</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Max Min Dim</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Status</th>
                  <th className="px-6 py-4 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {entries.map((entry) => {
                  const linkedTrees = trees.filter(t => entry.treeIds.includes(t.id));
                  const tableDataArray = linkedTrees.map(t => getTableBData(t.diameter));

                  const totalBaseReq = tableDataArray.reduce((sum, d) => sum + d.req, 0);
                  const maxMinDim = tableDataArray.length > 0 ? Math.max(...tableDataArray.map(d => d.dim)) : 0;

                  const adjustedReq = totalBaseReq * (entry.isCluster ? 0.95 : 1.0);
                  const isPass = entry.soilAreaProvided >= adjustedReq;

                  return (
                    <tr key={entry.id} className="hover:bg-emerald-50/30 transition-colors group">
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={entry.areaId}
                          onChange={(e) => updateEntry(entry.id, { areaId: e.target.value })}
                          className="w-full bg-transparent border-b border-transparent focus:border-emerald-500 outline-none text-sm font-bold text-slate-700"
                        />
                      </td>
                      <td className="px-6 py-4 max-w-xs">
                        <div className="flex flex-wrap gap-1.5 mb-2">
                          {linkedTrees.map(t => (
                            <span key={t.id} className="inline-flex items-center gap-1 bg-slate-100 text-slate-700 px-2 py-1 rounded text-[10px] font-bold group/tag">
                              {getTreeCode(t)}
                              <button 
                                onClick={() => removeTreeFromZone(entry.id, t.id)}
                                className="text-slate-400 hover:text-rose-500 transition-colors"
                              >
                                <X size={12} />
                              </button>
                            </span>
                          ))}
                        </div>
                        <select 
                          value=""
                          onChange={(e) => addTreeToZone(entry.id, e.target.value)}
                          className="w-full px-2 py-1 rounded bg-slate-50 border border-slate-200 text-[10px] font-medium focus:ring-1 focus:ring-emerald-500 outline-none"
                        >
                          <option value="">+ Add tree from inventory...</option>
                          {trees.map(t => (
                            <option key={t.id} value={t.id} disabled={entry.treeIds.includes(t.id)}>
                              {getTreeCode(t)} &mdash; {t.type || 'Unnamed'} ({t.diameter}m)
                            </option>
                          ))}
                        </select>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-1">
                            <input 
                                type="number" 
                                value={entry.soilAreaProvided}
                                onChange={(e) => updateEntry(entry.id, { soilAreaProvided: Number(e.target.value) })}
                                className="w-20 px-2 py-1.5 rounded border border-slate-200 text-sm font-bold focus:ring-1 focus:ring-emerald-500 outline-none"
                            />
                            <span className="text-xs text-slate-400 font-medium">m²</span>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <input 
                          type="checkbox" 
                          checked={entry.isCluster}
                          onChange={(e) => updateEntry(entry.id, { isCluster: e.target.checked })}
                          className="w-4 h-4 accent-emerald-600 rounded cursor-pointer"
                          title="Reduce total aggregate requirement by 5% for shared soil volumes"
                        />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex flex-col">
                            <span className="text-sm font-bold text-slate-800">{adjustedReq.toFixed(1)}m²</span>
                            {entry.isCluster && entry.treeIds.length > 0 && (
                              <span className="text-[9px] text-emerald-600 font-bold uppercase tracking-tighter">-5% Shared Vol</span>
                            )}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="text-xs font-mono font-bold text-slate-400">{maxMinDim > 0 ? `${maxMinDim}m` : '-'}</span>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-[10px] font-bold border ${isPass ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                          {isPass ? <CheckCircle2 size={12} /> : <XCircle size={12} />}
                          {isPass ? 'COMPLIANT' : 'SHORTFALL'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => removeEntry(entry.id)}
                          className="text-slate-300 hover:text-rose-500 transition-colors p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        <div className="p-4 bg-slate-50 border-t border-slate-100 text-[10px] font-medium uppercase text-slate-400 italic text-center flex items-center justify-center gap-2">
            <Info size={12} className="text-emerald-500" />
            Aggregated target is the sum of Table B area requirements for all linked trees in the zone.
        </div>
      </div>

      {/* Visual Planning Aid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-3xl flex gap-4">
            <div className="bg-indigo-100 p-3 rounded-2xl flex-shrink-0 h-fit">
                <Info className="text-indigo-600" size={24} />
            </div>
            <div>
                <h4 className="font-bold text-indigo-900 mb-2">Aggregate Volume Planning</h4>
                <p className="text-sm text-indigo-800 leading-relaxed">
                    When multiple trees share a soil zone, their individual root requirements are additive. However, shared biological activity often yields healthier results than isolated pits. The "Max Min Dim" ensures the zone is wide enough to support the largest tree in the group.
                </p>
            </div>
        </div>

        <div className="bg-amber-50 border border-amber-100 p-6 rounded-3xl flex gap-4">
            <div className="bg-amber-100 p-3 rounded-2xl flex-shrink-0 h-fit">
                <AlertCircle className="text-amber-600" size={24} />
            </div>
            <div>
                <h4 className="font-bold text-amber-900 mb-2">Clustering Logic</h4>
                <p className="text-sm text-amber-800 leading-relaxed">
                    By grouping trees together in a shared soil area (clustering), you can apply a **5% reduction** to the total required soil area. Root interlocking provides superior structural stability and nutrient sharing.
                </p>
            </div>
        </div>
      </div>
    </div>
  );
};

export interface TreeItem {
  id: string;
  qty: number;
  type: string;
  diameter: number;
  manualArea?: number; // User-provided area for compliance checking
}

export interface SoilEntry {
  id: string;
  areaId: string;
  treeIds: string[]; // References multiple TreeItem.ids
  soilAreaProvided: number;
  isCluster: boolean;
}

export interface AnalysisResponse {
  summary: string;
  recommendations: string[];
}

