            >
              <Layout size={16} /> Canopy
            </button>
            <button 
              onClick={() => setActiveTab('soil')}
              className={`flex items-center gap-2 px-6 py-2 rounded-full transition-all text-sm font-medium ${activeTab === 'soil' ? 'bg-emerald-500 text-white shadow-sm' : 'hover:bg-emerald-800/50 text-emerald-200'}`}
