      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Plus, Trash2, TreePine, AlertCircle, CheckCircle2, Info } from 'lucide-react';
import { TreeItem } from '../types';

interface Props {
  siteArea: number;
  setSiteArea: (v: number) => void;
  targetPct: number;
  setTargetPct: (v: number) => void;
  trees: TreeItem[];
  setTrees: (v: TreeItem[]) => void;
}

export const CanopyCalculator: React.FC<Props> = ({ siteArea, setSiteArea, targetPct, setTargetPct, trees, setTrees }) => {
  const calculateArea = (dia: number) => Math.PI * Math.pow(dia / 2, 2);

  const getClassification = (d: number): 'A' | 'B' | 'C' => {
    if (d >= 12) return 'C';
    if (d > 8) return 'B';
    return 'A';
  };

  const sortedTrees = [...trees].sort((a, b) => {
    const classA = getClassification(a.diameter);
    const classB = getClassification(b.diameter);
    if (classA !== classB) return classA.localeCompare(classB);
    return a.diameter - b.diameter;
  });

  const totalBioArea = sortedTrees.reduce((acc, t) => acc + calculateArea(t.diameter), 0);
  const totalCompliantCover = sortedTrees.reduce((acc, t) => acc + (t.compliantCover || 0), 0);

  const minRequired = siteArea * (targetPct / 100);
  const diff = totalCompliantCover - minRequired;
  const currentPct = siteArea > 0 ? (totalCompliantCover / siteArea) * 100 : 0;

  const chartData = [
    { name: 'Compliant Canopy', value: totalCompliantCover, color: '#10b981' },
    { name: 'Other Area', value: Math.max(0, siteArea - totalCompliantCover), color: '#e2e8f0' }
  ];

  const addTree = () => {
    const id = Math.random().toString(36).substr(2, 9);
    const defaultDia = 5.0;
    setTrees([...trees, { id, qty: 1, type: '', diameter: defaultDia, compliantCover: calculateArea(defaultDia) }]);
  };

  const removeTree = (id: string) => {
    setTrees(trees.filter(t => t.id !== id));
  };

  const updateTree = (id: string, updates: Partial<TreeItem>) => {
    setTrees(trees.map(t => t.id === id ? { ...t, ...updates } : t));
  };

  const counts = { A: 0, B: 0, C: 0 };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Configuration Panel */}
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-emerald-100 p-1.5 rounded-md"><TreePine size={18} className="text-emerald-600" /></div>
            Site Parameters
          </h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Total Site Area (m²)</label>
              <input 
                type="number" 
                value={siteArea}
                onChange={(e) => setSiteArea(Number(e.target.value))}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-all outline-none"
              />
              <p className="text-[10px] text-slate-400 mt-1 font-semibold italic">
                {siteArea < 1000 ? "Small Site (<1000m²): 10% target applied." : "Standard Site (≥1000m²): 20% target applied."}
              </p>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1 flex justify-between">
                Target Coverage <span>{targetPct}%</span>
              </label>
              <input 
                type="range" 
                min="0" max="100" 
                value={targetPct}
                onChange={(e) => setTargetPct(Number(e.target.value))}
                className="w-full accent-emerald-600 cursor-pointer"
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4">Compliance Summary</h2>
          <div className="space-y-4">
            <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
              <span className="text-sm text-slate-500">Min. Required</span>
              <span className="font-bold text-slate-800">{minRequired.toFixed(2)} m²</span>
            </div>
            <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
              <span className="text-sm text-slate-500">Total Compliant Cover</span>
              <span className="font-bold text-emerald-600">{totalCompliantCover.toFixed(2)} m²</span>
            </div>

            <div className={`p-4 rounded-xl flex items-center gap-3 ${diff >= 0 ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-rose-50 text-rose-700 border border-rose-100'}`}>
              {diff >= 0 ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
              <div>
                <p className="font-bold text-sm">{diff >= 0 ? 'Goal Met' : 'Shortfall Detected'}</p>
                <p className="text-xs opacity-90">{Math.abs(diff).toFixed(2)} m² {diff >= 0 ? 'above target' : 'below target'}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-64 relative">
          <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider text-center mb-2">Canopy Visualizer</h2>
          <ResponsiveContainer width="100%" height="80%">
            <PieChart>
              <Pie
                data={chartData}
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none mt-6">
            <span className="text-2xl font-bold text-slate-800">{currentPct.toFixed(1)}%</span>
            <span className="text-[10px] text-slate-400 font-medium tracking-widest">ACTUAL</span>
          </div>
        </div>
      </div>

      {/* Tree Inventory Table */}
      <div className="lg:col-span-2">
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div>
              <h2 className="text-xl font-bold text-slate-800">Proposed Tree Inventory</h2>
              <p className="text-sm text-slate-500">Manage canopy allocation and compliant coverage</p>
            </div>
            <button 
              onClick={addTree}
              className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg transition-colors font-medium text-sm shadow-sm"
            >
              <Plus size={18} /> Add Tree
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">No.</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Botanical Name</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Dia (m)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Bio Area (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-emerald-600 uppercase tracking-widest">Compliant Cover (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-rose-600 uppercase tracking-widest text-right">Non Compliant</th>
                  <th className="px-6 py-4 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {sortedTrees.map((tree) => {
                  const classification = getClassification(tree.diameter);
                  const code = `${classification}${(++counts[classification]).toString().padStart(2, '0')}`;
                  const bioArea = calculateArea(tree.diameter);
                  const compliant = tree.compliantCover || 0;
                  const nonCompliant = Math.max(0, bioArea - compliant);

                  return (
                    <tr key={tree.id} className="hover:bg-slate-50 transition-colors group">
                      <td className="px-6 py-4">
                        <span className="font-mono text-xs font-bold text-slate-600 bg-slate-100 px-2 py-1 rounded">
                          {code}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={tree.type}
                          onChange={(e) => updateTree(tree.id, { type: e.target.value })}
                          placeholder="e.g. Acer rubrum"
                          className="w-full bg-transparent border-b border-transparent hover:border-slate-200 focus:border-emerald-500 py-1 outline-none text-sm transition-all italic"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <input 
                          type="number" 
                          step="0.5"
                          value={tree.diameter}
                          onChange={(e) => updateTree(tree.id, { diameter: Number(e.target.value) })}
                          className="w-16 px-2 py-1.5 rounded border border-slate-200 focus:border-emerald-500 outline-none text-sm font-medium"
                        />
                      </td>
                      <td className="px-6 py-4 text-right font-medium text-slate-400 text-xs">
                        {bioArea.toFixed(1)}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-1">
                          <input 
                            type="number" 
                            step="0.1"
                            value={tree.compliantCover ?? ''}
                            onChange={(e) => updateTree(tree.id, { compliantCover: Number(e.target.value) })}
                            className="w-24 px-2 py-1.5 rounded border border-emerald-200 focus:ring-1 focus:ring-emerald-500 outline-none text-sm font-bold bg-emerald-50/30"
                          />
                          <span className="text-[10px] text-emerald-600 font-bold">m²</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className={`text-xs font-bold ${nonCompliant > 0 ? 'text-rose-500' : 'text-slate-300'}`}>
                          {nonCompliant.toFixed(1)} m²
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => removeTree(tree.id)}
                          className="text-slate-300 hover:text-rose-500 transition-colors p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              {sortedTrees.length > 0 && (
                <tfoot className="bg-slate-50 font-bold text-slate-700">
                  <tr>
                    <td className="px-6 py-4" colSpan={3}>Inventory Totals ({sortedTrees.length} trees)</td>
                    <td className="px-6 py-4 text-right text-xs text-slate-400">{totalBioArea.toFixed(1)}</td>
                    <td className="px-6 py-4 text-emerald-700">{totalCompliantCover.toFixed(1)} m²</td>
                    <td className="px-6 py-4 text-right text-rose-500">{Math.max(0, totalBioArea - totalCompliantCover).toFixed(1)} m²</td>
                    <td></td>
                  </tr>
                </tfoot>
              )}
              {sortedTrees.length === 0 && (
                <tbody>
                  <tr>
                    <td colSpan={7} className="px-6 py-12 text-center text-slate-400 italic">
                      No trees added yet.
                    </td>
                  </tr>
                </tbody>
              )}
            </table>
          </div>
          <div className="p-4 bg-slate-50 border-t border-slate-100 text-[10px] font-medium uppercase text-slate-400">
            <div className="flex justify-center gap-8 tracking-widest items-center">
              <span className="flex items-center gap-1"><Info size={12}/> Bio Area = π * (Dia/2)²</span>
              <span className="flex items-center gap-1"><Info size={12}/> Non Compliant = Bio Area - Compliant Cover</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Plus, Trash2, Shovel, Info, CheckCircle2, XCircle, AlertCircle, X, TreePine } from 'lucide-react';
import { SoilEntry, TreeItem } from '../types';

interface Props {
  entries: SoilEntry[];
  setEntries: (v: SoilEntry[]) => void;
  trees: TreeItem[];
}

export const DeepSoilCalculator: React.FC<Props> = ({ entries, setEntries, trees }) => {
  const addEntry = () => {
    const id = Math.random().toString(36).substr(2, 9);

    setEntries([...entries, { 
      id, 
      areaId: `Zone ${entries.length + 1}`, 
      treeIds: [], // Start with no trees linked
      soilAreaProvided: 25.0, 
      isCluster: false 
    }]);
  };

  const removeEntry = (id: string) => {
    setEntries(entries.filter(e => e.id !== id));
  };

  const updateEntry = (id: string, updates: Partial<SoilEntry>) => {
    setEntries(entries.map(e => e.id === id ? { ...e, ...updates } : e));
  };

  const addTreeToZone = (zoneId: string, treeId: string) => {
    if (!treeId) return;
    const entry = entries.find(e => e.id === zoneId);
    if (entry && !entry.treeIds.includes(treeId)) {
      updateEntry(zoneId, { treeIds: [...entry.treeIds, treeId] });
    }
  };

  const removeTreeFromZone = (zoneId: string, treeId: string) => {
    const entry = entries.find(e => e.id === zoneId);
    if (entry) {
      updateEntry(zoneId, { treeIds: entry.treeIds.filter(id => id !== treeId) });
    }
  };

  const getTableBData = (diameter: number) => {
    if (diameter < 4) return { req: 0, dim: 0, class: 'N/A' };
    if (diameter < 5) return { req: 12, dim: 2.5, class: 'A' };
    if (diameter < 6) return { req: 16, dim: 3.0, class: 'A' };
    if (diameter < 7) return { req: 25, dim: 3.5, class: 'A' };
    if (diameter < 8) return { req: 36, dim: 4.0, class: 'A' };
    if (diameter < 9) return { req: 49, dim: 4.5, class: 'B' };
    if (diameter < 10) return { req: 64, dim: 5.0, class: 'B' };
    if (diameter < 11) return { req: 81, dim: 5.5, class: 'B' };
    if (diameter < 12) return { req: 100, dim: 6.0, class: 'B' };
    if (diameter < 13) return { req: 121, dim: 6.5, class: 'C' };
    if (diameter < 14) return { req: 136, dim: 7.0, class: 'C' };
    return { req: 144, dim: 7.5, class: 'C' };
  };

  const getTreeCode = (tree: TreeItem) => {
    const getClassification = (d: number): 'A' | 'B' | 'C' => {
        if (d >= 12) return 'C';
        if (d >= 8) return 'B';
        return 'A';
    };

    const sameClass = trees
        .filter(t => getClassification(t.diameter) === getClassification(tree.diameter))
        .sort((a,b) => a.diameter - b.diameter);
    const index = sameClass.findIndex(t => t.id === tree.id) + 1;
    return `${getClassification(tree.diameter)}${index.toString().padStart(2, '0')}`;
  };

  const totalSoilProvided = entries.reduce((acc, curr) => acc + curr.soilAreaProvided, 0);

  return (
    <div className="space-y-6">
      {/* Informational Header */}
      <div className="bg-emerald-900 text-white p-8 rounded-3xl relative overflow-hidden shadow-xl">
        <div className="relative z-10">
          <h2 className="text-2xl font-bold mb-2 flex items-center gap-2">
            <Shovel size={28} /> Deep Soil Volume Assessment
          </h2>
          <p className="text-emerald-100/80 max-w-2xl mb-6">
            Ensuring adequate root volume is critical for tree health. This calculator applies **Table B** standards. For shared zones, requirements for all trees are aggregated.
          </p>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3 max-w-3xl">
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Small (Type A)</p>
                <p className="text-sm font-medium">12m² &ndash; 36m² Area Req.</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Medium (Type B)</p>
                <p className="text-sm font-medium">49m² &ndash; 100m² Area Req.</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Large (Type C)</p>
                <p className="text-sm font-medium">121m² &ndash; 144m² Area Req.</p>
            </div>
          </div>
        </div>
        <div className="absolute top-0 right-0 w-80 h-80 bg-emerald-500/10 rounded-full -translate-y-1/3 translate-x-1/3 blur-3xl"></div>
      </div>

      {/* Calculator Table */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Soil Allocation Log</h3>
            <p className="text-sm text-slate-500 italic">Assign trees from inventory to deep soil zones</p>
          </div>
          <button 
            onClick={addEntry}
            disabled={trees.length === 0}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl transition-all font-bold text-sm shadow-sm ${ trees.length === 0 ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200' : 'bg-emerald-600 hover:bg-emerald-700 text-white'}`}
          >
            <Plus size={18} /> Add Soil Zone
          </button>
        </div>

        {trees.length === 0 ? (
          <div className="p-12 text-center space-y-4">
            <div className="bg-rose-50 text-rose-500 p-4 rounded-full w-16 h-16 flex items-center justify-center mx-auto">
                <AlertCircle size={32} />
            </div>
            <div className="max-w-xs mx-auto">
                <p className="font-bold text-slate-800">No Trees Detected</p>
                <p className="text-sm text-slate-500">Please add trees in the Canopy tab first.</p>
            </div>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-200">
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Zone ID</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Linked Trees</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Provided Soil (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Cluster?</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Agg. Target</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Status</th>
                  <th className="px-6 py-4 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {entries.map((entry) => {
                  const linkedTrees = trees.filter(t => entry.treeIds.includes(t.id));
                  const tableDataArray = linkedTrees.map(t => getTableBData(t.diameter));
                  const totalBaseReq = tableDataArray.reduce((sum, d) => sum + d.req, 0);
                  const adjustedReq = totalBaseReq * (entry.isCluster ? 0.95 : 1.0);
                  const isPass = entry.soilAreaProvided >= adjustedReq;

                  return (
                    <tr key={entry.id} className="hover:bg-emerald-50/30 transition-colors group">
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={entry.areaId}
                          onChange={(e) => updateEntry(entry.id, { areaId: e.target.value })}
                          className="w-full bg-transparent border-b border-transparent focus:border-emerald-500 outline-none text-sm font-bold text-slate-700"
                        />
                      </td>
                      <td className="px-6 py-4 max-w-xs">
                        <div className="flex flex-wrap gap-1.5 mb-2">
                          {linkedTrees.map(t => (
                            <span key={t.id} className="inline-flex items-center gap-1 bg-slate-100 text-slate-700 px-2 py-1 rounded text-[10px] font-bold group/tag">
                              {getTreeCode(t)}
                              <button onClick={() => removeTreeFromZone(entry.id, t.id)} className="text-slate-400 hover:text-rose-500 transition-colors"><X size={12}/></button>
                            </span>
                          ))}
                        </div>
                        <select 
                          value=""
                          onChange={(e) => addTreeToZone(entry.id, e.target.value)}
                          className="w-full px-2 py-1 rounded bg-slate-50 border border-slate-200 text-[10px] font-medium focus:ring-1 focus:ring-emerald-500 outline-none"
                        >
                          <option value="">+ Add tree...</option>
                          {trees.map(t => (
                            <option key={t.id} value={t.id} disabled={entry.treeIds.includes(t.id)}>
                              {getTreeCode(t)} &mdash; {t.type || 'Unnamed'} ({t.diameter}m)
                            </option>
                          ))}
                        </select>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex items-center justify-end gap-1">
                            <input 
                                type="number" 
                                value={entry.soilAreaProvided}
                                onChange={(e) => updateEntry(entry.id, { soilAreaProvided: Number(e.target.value) })}
                                className="w-20 px-2 py-1.5 rounded border border-slate-200 text-sm font-bold text-right"
                            />
                            <span className="text-xs text-slate-400 font-medium">m²</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <input 
                          type="checkbox" 
                          checked={entry.isCluster}
                          onChange={(e) => updateEntry(entry.id, { isCluster: e.target.checked })}
                          className="w-4 h-4 accent-emerald-600"
                        />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex flex-col">
                            <span className="text-sm font-bold text-slate-800">{adjustedReq.toFixed(1)}m²</span>
                            {entry.isCluster && <span className="text-[9px] text-emerald-600 font-bold uppercase">-5% Vol</span>}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-[10px] font-bold border ${isPass ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                          {isPass ? 'Pass' : 'Fail'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button onClick={() => removeEntry(entry.id)} className="text-slate-300 hover:text-rose-500 transition-colors p-1"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              {entries.length > 0 && (
                <tfoot className="bg-slate-50 font-bold text-slate-700 border-t border-slate-200">
                  <tr>
                    <td className="px-6 py-4" colSpan={2}>Deep Soil Allocation Totals</td>
                    <td className="px-6 py-4 text-right text-emerald-700">{totalSoilProvided.toFixed(1)} m²</td>
                    <td className="px-6 py-4" colSpan={4}></td>
                  </tr>
                </tfoot>
              )}
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export interface TreeItem {
  id: string;
  qty: number;
  type: string;
  diameter: number;
  compliantCover?: number; // User-input: how much of the tree's canopy is compliant
}

export interface SoilEntry {
  id: string;
  areaId: string;
  treeIds: string[]; // References multiple TreeItem.ids
  soilAreaProvided: number;
  isCluster: boolean;
}

export interface AnalysisResponse {
  summary: string;
  recommendations: string[];
}

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Plus, Trash2, TreePine, AlertCircle, CheckCircle2, Info } from 'lucide-react';
import { TreeItem } from '../types';

interface Props {
  siteArea: number;
  setSiteArea: (v: number) => void;
  targetPct: number;
  setTargetPct: (v: number) => void;
  trees: TreeItem[];
  setTrees: (v: TreeItem[]) => void;
}

export const CanopyCalculator: React.FC<Props> = ({ siteArea, setSiteArea, targetPct, setTargetPct, trees, setTrees }) => {
  const calculateArea = (dia: number) => Math.PI * Math.pow(dia / 2, 2);

  const getClassification = (d: number): 'A' | 'B' | 'C' => {
    if (d >= 12) return 'C';
    if (d > 8) return 'B';
    return 'A';
  };

  const sortedTrees = [...trees].sort((a, b) => {
    const classA = getClassification(a.diameter);
    const classB = getClassification(b.diameter);
    if (classA !== classB) return classA.localeCompare(classB);
    return a.diameter - b.diameter;
  });

  const totalBioArea = sortedTrees.reduce((acc, t) => acc + calculateArea(t.diameter), 0);
  const totalCompliantCover = sortedTrees.reduce((acc, t) => acc + (t.compliantCover || 0), 0);
  const totalNonCompliant = totalBioArea - totalCompliantCover;

  const minRequired = siteArea * (targetPct / 100);
  const diff = totalCompliantCover - minRequired;
  const currentPct = siteArea > 0 ? (totalCompliantCover / siteArea) * 100 : 0;

  const chartData = [
    { name: 'Compliant Canopy', value: totalCompliantCover, color: '#10b981' },
    { name: 'Remaining Site', value: Math.max(0, siteArea - totalCompliantCover), color: '#e2e8f0' }
  ];

  const addTree = () => {
    const id = Math.random().toString(36).substr(2, 9);
    const dia = 5.0;
    const area = calculateArea(dia);
    setTrees([...trees, { id, qty: 1, type: '', diameter: dia, compliantCover: Number(area.toFixed(1)) }]);
  };

  const removeTree = (id: string) => {
    setTrees(trees.filter(t => t.id !== id));
  };

  const updateTree = (id: string, updates: Partial<TreeItem>) => {
    setTrees(trees.map(t => t.id === id ? { ...t, ...updates } : t));
  };

  const counts = { A: 0, B: 0, C: 0 };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Configuration Panel */}
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-emerald-100 p-1.5 rounded-md"><TreePine size={18} className="text-emerald-600" /></div>
            Site Parameters
          </h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Total Site Area (m²)</label>
              <input 
                type="number" 
                value={siteArea}
                onChange={(e) => setSiteArea(Number(e.target.value))}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 transition-all outline-none"
              />
              <p className="text-[10px] text-slate-400 mt-1 font-semibold italic">
                {siteArea < 1000 ? "Target 10% applied (Area < 1000m²)" : "Target 20% applied (Area ≥ 1000m²)"}
              </p>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1 flex justify-between">
                Target Coverage <span>{targetPct}%</span>
              </label>
              <input 
                type="range" 
                min="0" max="100" 
                value={targetPct}
                onChange={(e) => setTargetPct(Number(e.target.value))}
                className="w-full accent-emerald-600 cursor-pointer"
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4">Site Metrics</h2>
          <div className="space-y-4">
            <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
              <span className="text-sm text-slate-500">Min. Required</span>
              <span className="font-bold text-slate-800">{minRequired.toFixed(2)} m²</span>
            </div>
            <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
              <span className="text-sm text-slate-500">Compliant Total</span>
              <span className="font-bold text-emerald-600">{totalCompliantCover.toFixed(2)} m²</span>
            </div>

            <div className={`p-4 rounded-xl flex items-center gap-3 ${diff >= 0 ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-rose-50 text-rose-700 border border-rose-100'}`}>
              {diff >= 0 ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
              <div>
                <p className="font-bold text-sm">{diff >= 0 ? 'Compliance Met' : 'Shortfall'}</p>
                <p className="text-xs opacity-90">{Math.abs(diff).toFixed(2)} m² {diff >= 0 ? 'excess' : 'shortfall'}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-64 relative">
          <ResponsiveContainer width="100%" height="90%">
            <PieChart>
              <Pie
                data={chartData}
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none mt-4">
            <span className="text-2xl font-bold text-slate-800">{currentPct.toFixed(1)}%</span>
            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Compliant</span>
          </div>
        </div>
      </div>

      {/* Tree Inventory Table */}
      <div className="lg:col-span-2">
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div>
              <h2 className="text-xl font-bold text-slate-800">Proposed Tree Inventory</h2>
              <p className="text-sm text-slate-500 italic">Manage tree dimensions and compliant canopy areas</p>
            </div>
            <button 
              onClick={addTree}
              className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg transition-colors font-medium text-sm shadow-sm"
            >
              <Plus size={18} /> Add Tree
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Code</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Botanical Name</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Dia (m)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Required Area (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-emerald-600 uppercase tracking-widest">Compliant Cover (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-rose-600 uppercase tracking-widest text-right">Non Compliant Cover</th>
                  <th className="px-6 py-4 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {sortedTrees.map((tree) => {
                  const classification = getClassification(tree.diameter);
                  const code = `${classification}${(++counts[classification]).toString().padStart(2, '0')}`;
                  const requiredArea = calculateArea(tree.diameter);
                  const compliant = tree.compliantCover || 0;
                  const nonCompliant = Math.max(0, requiredArea - compliant);

                  return (
                    <tr key={tree.id} className="hover:bg-slate-50 transition-colors group">
                      <td className="px-6 py-4">
                        <span className="font-mono text-[10px] font-bold text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded">
                          {code}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={tree.type}
                          onChange={(e) => updateTree(tree.id, { type: e.target.value })}
                          placeholder="e.g. Quercus rubra"
                          className="w-full bg-transparent border-b border-transparent hover:border-slate-200 focus:border-emerald-500 py-1 outline-none text-sm transition-all italic"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <input 
                          type="number" 
                          step="0.1"
                          value={tree.diameter}
                          onChange={(e) => updateTree(tree.id, { diameter: Number(e.target.value) })}
                          className="w-16 px-2 py-1 rounded border border-slate-200 text-sm font-medium focus:ring-1 focus:ring-emerald-500 outline-none"
                        />
                      </td>
                      <td className="px-6 py-4 text-right text-xs text-slate-400 font-medium">
                        {requiredArea.toFixed(1)}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-1">
                          <input 
                            type="number" 
                            step="0.1"
                            value={tree.compliantCover ?? ''}
                            onChange={(e) => updateTree(tree.id, { compliantCover: Number(e.target.value) })}
                            className="w-24 px-2 py-1 rounded border border-emerald-200 focus:ring-1 focus:ring-emerald-500 outline-none text-sm font-bold bg-emerald-50/20"
                          />
                          <span className="text-[10px] text-emerald-500 font-bold">m²</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className={`text-xs font-bold ${nonCompliant > 0.1 ? 'text-rose-500' : 'text-slate-300'}`}>
                          {nonCompliant.toFixed(1)} m²
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => removeTree(tree.id)}
                          className="text-slate-200 hover:text-rose-500 transition-colors p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              {sortedTrees.length > 0 && (
                <tfoot className="bg-slate-50 font-bold text-slate-700 border-t border-slate-200">
                  <tr>
                    <td className="px-6 py-4" colSpan={2}>Inventory Totals</td>
                    <td className="px-6 py-4">{sortedTrees.length} Trees</td>
                    <td className="px-6 py-4 text-right text-xs text-slate-400">{totalBioArea.toFixed(1)}</td>
                    <td className="px-6 py-4 text-emerald-700">{totalCompliantCover.toFixed(1)} m²</td>
                    <td className="px-6 py-4 text-right text-rose-500">{totalNonCompliant.toFixed(1)} m²</td>
                    <td></td>
                  </tr>
                </tfoot>
              )}
              {sortedTrees.length === 0 && (
                <tbody>
                  <tr>
                    <td colSpan={7} className="px-6 py-12 text-center text-slate-400 italic font-medium">
                      The inventory is currently empty. Add trees to begin calculation.
                    </td>
                  </tr>
                </tbody>
              )}
            </table>
          </div>
          <div className="p-4 bg-slate-50 border-t border-slate-100 text-[9px] font-bold uppercase text-slate-400 flex justify-center gap-6">
            <span className="flex items-center gap-1"><Info size={10} /> REQUIRED AREA: BIOLOGICAL CANOPY (πr²)</span>
            <span className="flex items-center gap-1"><Info size={10} /> NON COMPLIANT: REQUIRED AREA - COMPLIANT COVER</span>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Plus, Trash2, Shovel, Info, CheckCircle2, XCircle, AlertCircle, X } from 'lucide-react';
import { SoilEntry, TreeItem } from '../types';

interface Props {
  entries: SoilEntry[];
  setEntries: (v: SoilEntry[]) => void;
  trees: TreeItem[];
}

export const DeepSoilCalculator: React.FC<Props> = ({ entries, setEntries, trees }) => {
  const addEntry = () => {
    const id = Math.random().toString(36).substr(2, 9);

    setEntries([...entries, { 
      id, 
      areaId: `Zone ${entries.length + 1}`, 
      treeIds: [], 
      soilAreaProvided: 25.0, 
      isCluster: false 
    }]);
  };

  const removeEntry = (id: string) => {
    setEntries(entries.filter(e => e.id !== id));
  };

  const updateEntry = (id: string, updates: Partial<SoilEntry>) => {
    setEntries(entries.map(e => e.id === id ? { ...e, ...updates } : e));
  };

  const addTreeToZone = (zoneId: string, treeId: string) => {
    if (!treeId) return;
    const entry = entries.find(e => e.id === zoneId);
    if (entry && !entry.treeIds.includes(treeId)) {
      updateEntry(zoneId, { treeIds: [...entry.treeIds, treeId] });
    }
  };

  const removeTreeFromZone = (zoneId: string, treeId: string) => {
    const entry = entries.find(e => e.id === zoneId);
    if (entry) {
      updateEntry(zoneId, { treeIds: entry.treeIds.filter(id => id !== treeId) });
    }
  };

  const getTableBData = (diameter: number) => {
    if (diameter < 4) return { req: 0, dim: 0, class: 'N/A' };
    if (diameter < 5) return { req: 12, dim: 2.5, class: 'A' };
    if (diameter < 6) return { req: 16, dim: 3.0, class: 'A' };
    if (diameter < 7) return { req: 25, dim: 3.5, class: 'A' };
    if (diameter < 8) return { req: 36, dim: 4.0, class: 'A' };
    if (diameter < 9) return { req: 49, dim: 4.5, class: 'B' };
    if (diameter < 10) return { req: 64, dim: 5.0, class: 'B' };
    if (diameter < 11) return { req: 81, dim: 5.5, class: 'B' };
    if (diameter < 12) return { req: 100, dim: 6.0, class: 'B' };
    if (diameter < 13) return { req: 121, dim: 6.5, class: 'C' };
    if (diameter < 14) return { req: 136, dim: 7.0, class: 'C' };
    return { req: 144, dim: 7.5, class: 'C' };
  };

  const getTreeCode = (tree: TreeItem) => {
    const getClassification = (d: number): 'A' | 'B' | 'C' => {
        if (d >= 12) return 'C';
        if (d >= 8) return 'B';
        return 'A';
    };

    const sameClass = trees
        .filter(t => getClassification(t.diameter) === getClassification(tree.diameter))
        .sort((a,b) => a.diameter - b.diameter);
    const index = sameClass.findIndex(t => t.id === tree.id) + 1;
    return `${getClassification(tree.diameter)}${index.toString().padStart(2, '0')}`;
  };

  const totalSoilProvided = entries.reduce((acc, curr) => acc + curr.soilAreaProvided, 0);

  return (
    <div className="space-y-6">
      {/* Informational Header */}
      <div className="bg-emerald-900 text-white p-8 rounded-3xl relative overflow-hidden shadow-xl">
        <div className="relative z-10">
          <h2 className="text-2xl font-bold mb-2 flex items-center gap-2">
            <Shovel size={28} /> Deep Soil Volume Assessment
          </h2>
          <p className="text-emerald-100/80 max-w-2xl mb-6">
            Ensuring adequate root volume is critical for tree health. Minimum soil area and dimension standards apply based on tree mature size.
          </p>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3 max-w-3xl">
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Small (Type A)</p>
                <p className="text-sm font-medium">Min Dim: 2.5m - 4.0m</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Medium (Type B)</p>
                <p className="text-sm font-medium">Min Dim: 4.5m - 6.0m</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Large (Type C)</p>
                <p className="text-sm font-medium">Min Dim: 6.5m - 7.5m</p>
            </div>
          </div>
        </div>
        <div className="absolute top-0 right-0 w-80 h-80 bg-emerald-500/10 rounded-full -translate-y-1/3 translate-x-1/3 blur-3xl"></div>
      </div>

      {/* Calculator Table */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Soil Allocation Log</h3>
            <p className="text-sm text-slate-500 italic">Assign trees from inventory to deep soil zones</p>
          </div>
          <button 
            onClick={addEntry}
            disabled={trees.length === 0}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl transition-all font-bold text-sm shadow-sm ${ trees.length === 0 ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200' : 'bg-emerald-600 hover:bg-emerald-700 text-white'}`}
          >
            <Plus size={18} /> Add Soil Zone
          </button>
        </div>

        {trees.length === 0 ? (
          <div className="p-12 text-center space-y-4">
            <div className="bg-rose-50 text-rose-500 p-4 rounded-full w-16 h-16 flex items-center justify-center mx-auto">
                <AlertCircle size={32} />
            </div>
            <div className="max-w-xs mx-auto">
                <p className="font-bold text-slate-800">No Trees Detected</p>
                <p className="text-sm text-slate-500">Please add trees in the Canopy tab first.</p>
            </div>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-200">
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Zone ID</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Linked Trees</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Provided Soil (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Cluster?</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Agg. Target</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Req. Min Dim</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Status</th>
                  <th className="px-6 py-4 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {entries.map((entry) => {
                  const linkedTrees = trees.filter(t => entry.treeIds.includes(t.id));
                  const tableDataArray = linkedTrees.map(t => getTableBData(t.diameter));
                  const totalBaseReq = tableDataArray.reduce((sum, d) => sum + d.req, 0);
                  const maxRequiredDim = tableDataArray.length > 0 ? Math.max(...tableDataArray.map(d => d.dim)) : 0;
                  const adjustedReq = totalBaseReq * (entry.isCluster ? 0.95 : 1.0);
                  const isPass = entry.soilAreaProvided >= adjustedReq;

                  return (
                    <tr key={entry.id} className={`hover:bg-emerald-50/30 transition-colors group ${!isPass ? 'bg-rose-50/20' : ''}`}>
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={entry.areaId}
                          onChange={(e) => updateEntry(entry.id, { areaId: e.target.value })}
                          className="w-full bg-transparent border-b border-transparent focus:border-emerald-500 outline-none text-sm font-bold text-slate-700"
                        />
                      </td>
                      <td className="px-6 py-4 max-w-xs">
                        <div className="flex flex-wrap gap-1.5 mb-2">
                          {linkedTrees.map(t => (
                            <span key={t.id} className="inline-flex items-center gap-1 bg-white text-slate-700 px-2 py-1 rounded text-[10px] font-bold shadow-sm border border-slate-100 group/tag">
                              {getTreeCode(t)}
                              <button onClick={() => removeTreeFromZone(entry.id, t.id)} className="text-slate-400 hover:text-rose-500 transition-colors"><X size={12}/></button>
                            </span>
                          ))}
                        </div>
                        <select 
                          value=""
                          onChange={(e) => addTreeToZone(entry.id, e.target.value)}
                          className="w-full px-2 py-1 rounded bg-slate-50 border border-slate-200 text-[10px] font-medium focus:ring-1 focus:ring-emerald-500 outline-none"
                        >
                          <option value="">+ Add tree...</option>
                          {trees.map(t => (
                            <option key={t.id} value={t.id} disabled={entry.treeIds.includes(t.id)}>
                              {getTreeCode(t)} &mdash; {t.type || 'Unnamed'} ({t.diameter}m)
                            </option>
                          ))}
                        </select>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex items-center justify-end gap-2">
                            {!isPass && <AlertCircle size={14} className="text-rose-500 animate-pulse" />}
                            <div className="flex items-center gap-1">
                                <input 
                                    type="number" 
                                    value={entry.soilAreaProvided}
                                    onChange={(e) => updateEntry(entry.id, { soilAreaProvided: Number(e.target.value) })}
                                    className={`w-20 px-2 py-1.5 rounded border text-sm font-bold text-right transition-all outline-none ${
                                      isPass 
                                      ? 'border-slate-200 focus:border-emerald-500' 
                                      : 'border-rose-300 bg-rose-50 text-rose-700 focus:ring-1 focus:ring-rose-500'
                                    }`}
                                />
                                <span className="text-xs text-slate-400 font-medium">m²</span>
                            </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <input 
                          type="checkbox" 
                          checked={entry.isCluster}
                          onChange={(e) => updateEntry(entry.id, { isCluster: e.target.checked })}
                          className="w-4 h-4 accent-emerald-600 rounded cursor-pointer"
                        />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex flex-col">
                            <span className="text-sm font-bold text-slate-800">{adjustedReq.toFixed(1)}m²</span>
                            {entry.isCluster && entry.treeIds.length > 0 && <span className="text-[9px] text-emerald-600 font-bold uppercase">-5% Cluster</span>}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="text-sm font-mono font-bold text-slate-600">
                          {maxRequiredDim > 0 ? `${maxRequiredDim.toFixed(1)}m` : '-'}
                        </span>
