{
  "name": "Canopy & Soil Calculator",
  "description": "A professional-grade calculator for urban planners and landscape architects to manage tree canopy targets and deep soil volume requirements.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import { GoogleGenAI, Type } from "@google/genai";
import { TreeItem, SoilEntry } from "../types";

export interface TreeRecommendation {
  botanicalName: string;
  commonName: string;
  matureDiameter: number;
  description: string;
  imageUrl?: string;
  sourceUrl?: string;
}

export const getAIPlanningInsights = async (
  siteArea: number,
  targetPct: number,
  trees: TreeItem[],
  soilEntries: SoilEntry[]
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    As an Urban Landscape Architect, analyze this site:
    Total Site Area: ${siteArea} m2
    Target Canopy Percentage: ${targetPct}%
    Current Trees: ${JSON.stringify(trees)}
    Soil Provisions: ${JSON.stringify(soilEntries)}

    Provide a concise professional summary and 3-4 actionable recommendations to improve canopy health or meet urban planning targets.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          recommendations: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "recommendations"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const getTreeData = async (query: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Provide biological data for the tree species: "${query}".
    Focus on the mature canopy spread (diameter) in meters.
    If it's a range, provide the average typical mature diameter.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          botanicalName: { type: Type.STRING },
          commonName: { type: Type.STRING },
          matureDiameter: { type: Type.NUMBER, description: "Average mature diameter in meters" },
          description: { type: Type.STRING, description: "Short 1-sentence description of growth habit" }
        },
        required: ["botanicalName", "commonName", "matureDiameter"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const getTreeRecommendationsByPostcode = async (postcode: string): Promise<{ recommendations: TreeRecommendation[], sources: { title: string, uri: string }[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Search for tree species suitable for urban planting in Australia postcode ${postcode}. 
    Reference information from 'Which Plant Where' (whichplantwhere.com.au).
    Suggest exactly 3 distinct tree species (mix of sizes: A < 8m, B 8-12m, C > 12m). 
    For each, provide: botanicalName, commonName, matureDiameter (meters), and a brief description.
    Also prioritize species that are resilient to the climate of that specific postcode.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  // Since we use Google Search, response.text might contain the JSON wrapped in markdown or just the JSON.
  // We'll use a schema-less approach but prompt for JSON format, then parse.
  // Better approach: use generateContent with JSON mode if we don't need Search, 
  // but Search is required for specific postcodes/up-to-date data.

  // Re-requesting with schema but no tools for final formatting if needed, 
  // or just parsing from the text. For reliability with grounding, we parse grounding metadata.

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.filter(chunk => chunk.web)
    ?.map(chunk => ({ title: chunk.web!.title || 'Source', uri: chunk.web!.uri })) || [];

  // Re-parsing the JSON from the text
  const jsonMatch = response.text.match(/\[[\s\S]*\]/);
  const recommendations = jsonMatch ? JSON.parse(jsonMatch[0]) : [];

  return { recommendations, sources };
};

export const generateTreeImage = async (treeName: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A photorealistic architectural visualization of a mature ${treeName} tree in an Australian urban garden setting, soft natural lighting, high resolution.` }]
      }
    });

    const imagePart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (imagePart?.inlineData?.data) {
      return `data:image/png;base64,${imagePart.inlineData.data}`;
    }
  } catch (e) {
    console.error("Failed to generate tree image", e);
  }
  return null;
};

import React, { useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Plus, Trash2, TreePine, AlertCircle, CheckCircle2, Info, Search, Loader2, Sparkles, MapPin, Image as ImageIcon, ExternalLink } from 'lucide-react';
import { TreeItem } from '../types';
import { getTreeData, getTreeRecommendationsByPostcode, generateTreeImage, TreeRecommendation } from '../services/geminiService';

interface Props {
  siteArea: number;
  setSiteArea: (v: number) => void;
  targetPct: number;
  setTargetPct: (v: number) => void;
  trees: TreeItem[];
  setTrees: (v: TreeItem[]) => void;
}

export const CanopyCalculator: React.FC<Props> = ({ siteArea, setSiteArea, targetPct, setTargetPct, trees, setTrees }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [postcode, setPostcode] = useState('');
  const [searchLoading, setSearchLoading] = useState(false);
  const [recommendations, setRecommendations] = useState<TreeRecommendation[]>([]);
  const [sources, setSources] = useState<{ title: string, uri: string }[]>([]);

  const calculateArea = (dia: number) => Math.PI * Math.pow(dia / 2, 2);

  const getClassification = (d: number): 'A' | 'B' | 'C' => {
    if (d >= 12) return 'C';
    if (d >= 8) return 'B';
    return 'A';
  };

  const sortedTrees = [...trees].sort((a, b) => {
    const classA = getClassification(a.diameter);
    const classB = getClassification(b.diameter);
    if (classA !== classB) return classA.localeCompare(classB);
    return a.diameter - b.diameter;
  });

  const treeTypeCounts = {
    A: trees.filter(t => getClassification(t.diameter) === 'A').length,
    B: trees.filter(t => getClassification(t.diameter) === 'B').length,
    C: trees.filter(t => getClassification(t.diameter) === 'C').length,
  };

  const totalBioArea = sortedTrees.reduce((acc, t) => acc + calculateArea(t.diameter), 0);
  const totalCompliantCover = sortedTrees.reduce((acc, t) => acc + (t.compliantCover || 0), 0);
  const totalNonCompliant = Math.max(0, totalBioArea - totalCompliantCover);

  const minRequired = siteArea * (targetPct / 100);
  const diff = totalCompliantCover - minRequired;
  const currentPct = siteArea > 0 ? (totalCompliantCover / siteArea) * 100 : 0;

  const chartData = [
    { name: 'Compliant Canopy', value: totalCompliantCover, color: '#10b981' },
    { name: 'Remaining Site', value: Math.max(0, siteArea - totalCompliantCover), color: '#e2e8f0' }
  ];

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!postcode.trim() && !searchQuery.trim()) return;
    setSearchLoading(true);
    setRecommendations([]);
    setSources([]);

    try {
      let results: TreeRecommendation[] = [];
      let foundSources: { title: string, uri: string }[] = [];

      if (postcode.trim()) {
        const { recommendations: recs, sources: src } = await getTreeRecommendationsByPostcode(postcode);
        results = recs;
        foundSources = src;
      } else {
        const single = await getTreeData(searchQuery);
        results = [{
          botanicalName: single.botanicalName,
          commonName: single.commonName,
          matureDiameter: single.matureDiameter,
          description: single.description || "Found via search"
        }];
      }

      // Limit to 3 results as requested
      const top3 = results.slice(0, 3);

      // Generate images for results
      const resultsWithImages = await Promise.all(top3.map(async (res) => ({
        ...res,
        imageUrl: await generateTreeImage(res.botanicalName) || undefined
      })));

      setRecommendations(resultsWithImages);
      setSources(foundSources);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
    }
  };

  const addTree = (customData?: { type: string; diameter: number }) => {
    const id = Math.random().toString(36).substr(2, 9);
    const dia = customData?.diameter ?? 5.0;
    const area = calculateArea(dia);
    setTrees([...trees, { 
      id, 
      qty: 1, 
      type: customData?.type ?? '', 
      diameter: dia, 
      compliantCover: Number(area.toFixed(1)) 
    }]);
    if (customData) setRecommendations([]);
  };

  const removeTree = (id: string) => {
    setTrees(trees.filter(t => t.id !== id));
  };

  const updateTree = (id: string, updates: Partial<TreeItem>) => {
    setTrees(trees.map(t => t.id === id ? { ...t, ...updates } : t));
  };

  const codeCounts = { A: 0, B: 0, C: 0 };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Configuration Panel */}
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-emerald-100 p-1.5 rounded-md"><TreePine size={18} className="text-emerald-600" /></div>
            Site Parameters
          </h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Total Site Area (m²)</label>
              <input 
                type="number" 
                value={siteArea}
                onChange={(e) => setSiteArea(Number(e.target.value))}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 transition-all outline-none"
              />
              <p className="text-[10px] text-slate-400 mt-1 font-semibold italic">
                {siteArea < 1000 ? "Target 10% applied (Area < 1000m²)" : "Target 20% applied (Area ≥ 1000m²)"}
              </p>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1 flex justify-between">
                Target Coverage <span>{targetPct}%</span>
              </label>
              <input 
                type="range" 
                min="0" max="100" 
                value={targetPct}
                onChange={(e) => setTargetPct(Number(e.target.value))}
                className="w-full accent-emerald-600 cursor-pointer"
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-blue-100 p-1.5 rounded-md"><CheckCircle2 size={18} className="text-blue-600" /></div>
            Site Metrics
          </h2>
          <div className="space-y-4">
            <div className="p-4 bg-slate-50 rounded-xl space-y-3">
              <div className="flex justify-between items-center border-b border-slate-200 pb-2">
                <span className="text-sm font-bold text-slate-600">Total Tree Number</span>
                <span className="text-lg font-black text-slate-800">{trees.length}</span>
              </div>
              <div className="grid grid-cols-3 gap-2 text-center pt-1">
                <div className="bg-white p-2 rounded-lg border border-slate-100 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase">A</p>
                  <p className="text-sm font-black text-indigo-600">{treeTypeCounts.A}</p>
