{
  "name": "Canopy & Soil Calculator",
  "description": "A professional-grade calculator for urban planners and landscape architects to manage tree canopy targets and deep soil volume requirements.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import { GoogleGenAI, Type } from "@google/genai";
import { TreeItem, SoilEntry } from "../types";

export interface TreeRecommendation {
  botanicalName: string;
  commonName: string;
  matureDiameterRange: string;
  description: string;
  imageUrl?: string;
  sourceUrl?: string;
}

export const getAIPlanningInsights = async (
  siteArea: number,
  targetPct: number,
  trees: TreeItem[],
  soilEntries: SoilEntry[]
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    As an Urban Landscape Architect, analyze this site:
    Total Site Area: ${siteArea} m2
    Target Canopy Percentage: ${targetPct}%
    Current Trees: ${JSON.stringify(trees)}
    Soil Provisions: ${JSON.stringify(soilEntries)}

    Provide a concise professional summary and 3-4 actionable recommendations to improve canopy health or meet urban planning targets.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          recommendations: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "recommendations"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const getTreeRecommendationsByCriteria = async (postcode: string, minDiameter: number): Promise<{ recommendations: TreeRecommendation[], sources: any[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Using information from 'Which Plant Where' (whichplantwhere.com.au), search for 3 tree species suitable for urban planting in Australia postcode ${postcode}.
    Each tree must have a mature canopy spread of at least ${minDiameter}m.
    Return the data in a JSON array. 
    Include: botanicalName, commonName, matureDiameterRange (e.g. "5-8m"), and a brief description.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

  // Extract JSON from text response
  const text = response.text;
  const jsonStart = text.indexOf('[');
  const jsonEnd = text.lastIndexOf(']') + 1;
  const jsonStr = text.substring(jsonStart, jsonEnd);

  try {
    return { recommendations: JSON.parse(jsonStr), sources };
  } catch (e) {
    console.error("JSON Parse Error", e);
    return { recommendations: [], sources };
  }
};

export const generateTreeImage = async (treeName: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A photorealistic render of a mature ${treeName} tree in an urban garden, high quality architectural visualization.` }]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (part?.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  } catch (e) {
    console.error("Image Gen Error", e);
  }
  return null;
};

import React, { useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Plus, Trash2, TreePine, AlertCircle, CheckCircle2, Info, Search, Loader2, Sparkles, MapPin, Ruler, Image as ImageIcon } from 'lucide-react';
import { TreeItem } from '../types';
import { getTreeRecommendationsByCriteria, generateTreeImage, TreeRecommendation } from '../services/geminiService';

interface Props {
  siteArea: number;
  setSiteArea: (v: number) => void;
  targetPct: number;
  setTargetPct: (v: number) => void;
  trees: TreeItem[];
  setTrees: (v: TreeItem[]) => void;
}

export const CanopyCalculator: React.FC<Props> = ({ siteArea, setSiteArea, targetPct, setTargetPct, trees, setTrees }) => {
  const [minDiameter, setMinDiameter] = useState<string>('5');
  const [postcode, setPostcode] = useState<string>('');
  const [searchLoading, setSearchLoading] = useState(false);
  const [recommendations, setRecommendations] = useState<TreeRecommendation[]>([]);

  const calculateArea = (dia: number) => Math.PI * Math.pow(dia / 2, 2);

  const getClassification = (d: number): 'A' | 'B' | 'C' => {
    if (d >= 12) return 'C';
    if (d >= 8) return 'B';
    return 'A';
  };

  const sortedTrees = [...trees].sort((a, b) => {
    const classA = getClassification(a.diameter);
    const classB = getClassification(b.diameter);
    if (classA !== classB) return classA.localeCompare(classB);
    return a.diameter - b.diameter;
  });

  const treeTypeCounts = {
    A: trees.filter(t => getClassification(t.diameter) === 'A').length,
    B: trees.filter(t => getClassification(t.diameter) === 'B').length,
    C: trees.filter(t => getClassification(t.diameter) === 'C').length,
  };

  const totalBioArea = sortedTrees.reduce((acc, t) => acc + calculateArea(t.diameter), 0);
  const totalCompliantCover = sortedTrees.reduce((acc, t) => acc + (t.compliantCover || 0), 0);
  const totalNonCompliant = Math.max(0, totalBioArea - totalCompliantCover);

  const minRequired = siteArea * (targetPct / 100);
  const diff = totalCompliantCover - minRequired;
  const currentPct = siteArea > 0 ? (totalCompliantCover / siteArea) * 100 : 0;

  const chartData = [
    { name: 'Compliant Canopy', value: totalCompliantCover, color: '#10b981' },
    { name: 'Remaining Site', value: Math.max(0, siteArea - totalCompliantCover), color: '#e2e8f0' }
  ];

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!postcode.trim() || !minDiameter) return;
    setSearchLoading(true);
    setRecommendations([]);

    try {
      const { recommendations: recs } = await getTreeRecommendationsByCriteria(postcode, Number(minDiameter));

      // Fetch images for each recommendation in parallel
      const enrichedRecs = await Promise.all(recs.map(async (rec) => {
        const imageUrl = await generateTreeImage(rec.botanicalName);
        return { ...rec, imageUrl: imageUrl || undefined };
      }));

      setRecommendations(enrichedRecs);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
    }
  };

  const addTree = (customData?: { type: string; diameter: number }) => {
    const id = Math.random().toString(36).substr(2, 9);
    const dia = customData?.diameter ?? 5.0;
    const area = calculateArea(dia);
    setTrees([...trees, { 
      id, 
      qty: 1, 
      type: customData?.type ?? '', 
      diameter: dia, 
      compliantCover: Number(area.toFixed(1)) 
    }]);
  };

  const removeTree = (id: string) => {
    setTrees(trees.filter(t => t.id !== id));
  };

  const updateTree = (id: string, updates: Partial<TreeItem>) => {
    setTrees(trees.map(t => t.id === id ? { ...t, ...updates } : t));
  };

  const codeCounts = { A: 0, B: 0, C: 0 };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Configuration Panel */}
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-emerald-100 p-1.5 rounded-md"><TreePine size={18} className="text-emerald-600" /></div>
            Site Parameters
          </h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Total Site Area (m²)</label>
              <input 
                type="number" 
                value={siteArea}
                onChange={(e) => setSiteArea(Number(e.target.value))}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 transition-all outline-none"
              />
              <p className="text-[10px] text-slate-400 mt-1 font-semibold italic">
                {siteArea < 1000 ? "Target 10% applied (Area < 1000m²)" : "Target 20% applied (Area ≥ 1000m²)"}
              </p>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1 flex justify-between">
                Target Coverage <span>{targetPct}%</span>
              </label>
              <input 
                type="range" 
                min="0" max="100" 
                value={targetPct}
                onChange={(e) => setTargetPct(Number(e.target.value))}
                className="w-full accent-emerald-600 cursor-pointer"
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-blue-100 p-1.5 rounded-md"><CheckCircle2 size={18} className="text-blue-600" /></div>
            Site Metrics
          </h2>
          <div className="space-y-4">
            <div className="p-4 bg-slate-50 rounded-xl space-y-3">
              <div className="flex justify-between items-center border-b border-slate-200 pb-2">
                <span className="text-sm font-bold text-slate-600">Total Tree Number</span>
                <span className="text-lg font-black text-slate-800">{trees.length}</span>
              </div>
              <div className="grid grid-cols-3 gap-2 text-center pt-1">
                <div className="bg-white p-2 rounded-lg border border-slate-100 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">A</p>
                  <p className="text-sm font-black text-indigo-600">{treeTypeCounts.A}</p>
                </div>
                <div className="bg-white p-2 rounded-lg border border-slate-100 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">B</p>
                  <p className="text-sm font-black text-emerald-600">{treeTypeCounts.B}</p>
                </div>
                <div className="bg-white p-2 rounded-lg border border-slate-100 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">C</p>
                  <p className="text-sm font-black text-amber-600">{treeTypeCounts.C}</p>
                </div>
              </div>
            </div>

            <div className="flex justify-between items-center px-3 py-2 bg-slate-50 rounded-xl">
              <span className="text-xs font-medium text-slate-500">Min. Required</span>
              <span className="text-sm font-bold text-slate-800">{minRequired.toFixed(2)} m²</span>
            </div>
            <div className="flex justify-between items-center px-3 py-2 bg-slate-50 rounded-xl">
              <span className="text-xs font-medium text-slate-500">Compliant Total</span>
              <span className="text-sm font-bold text-emerald-600">{totalCompliantCover.toFixed(2)} m²</span>
            </div>

            <div className={`p-4 rounded-xl flex items-center gap-3 ${diff >= 0 ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-rose-50 text-rose-700 border border-rose-100'}`}>
              {diff >= 0 ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
              <div>
                <p className="font-bold text-sm">{diff >= 0 ? 'Compliance Met' : 'Shortfall'}</p>
                <p className="text-xs opacity-90">{Math.abs(diff).toFixed(2)} m² {diff >= 0 ? 'excess' : 'shortfall'}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-48 relative">
          <ResponsiveContainer width="100%" height="90%">
            <PieChart>
              <Pie
                data={chartData}
                innerRadius={50}
                outerRadius={70}
                paddingAngle={5}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none mt-4">
            <span className="text-xl font-bold text-slate-800">{currentPct.toFixed(1)}%</span>
            <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">Compliant</span>
          </div>
        </div>
      </div>

      {/* Tree Inventory Table */}
      <div className="lg:col-span-2 space-y-6">
        {/* Tree Lookup Tool */}
        <div className="bg-emerald-900 text-white p-6 rounded-3xl shadow-xl relative overflow-hidden">
          <div className="relative z-10">
            <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
              <Sparkles size={22} className="text-emerald-300" /> Tree Finder & Location Matching
            </h3>
            <p className="text-emerald-100/70 text-sm mb-6 max-w-xl">
              Discover species using data from <span className="font-bold text-emerald-200 underline underline-offset-4 decoration-emerald-500/50">Which Plant Where</span> tailored to your Australian postcode.
            </p>
            <form onSubmit={handleSearch} className="grid grid-cols-1 md:grid-cols-3 gap-3 items-end">
              <div>
                <label className="block text-[10px] uppercase font-bold text-emerald-300 mb-1 tracking-widest">Postcode</label>
                <div className="relative">
                  <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-emerald-400" size={16} />
                  <input 
                    type="text" 
                    value={postcode}
                    onChange={(e) => setPostcode(e.target.value)}
                    placeholder="e.g. 3000"
                    className="w-full bg-white/10 border border-white/20 rounded-xl py-2 pl-10 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500 placeholder:text-emerald-100/40"
                  />
                </div>
              </div>
              <div>
                <label className="block text-[10px] uppercase font-bold text-emerald-300 mb-1 tracking-widest">Min. Diameter (m)</label>
                <div className="relative">
                  <Ruler className="absolute left-3 top-1/2 -translate-y-1/2 text-emerald-400" size={16} />
                  <input 
                    type="number" 
                    value={minDiameter}
                    onChange={(e) => setMinDiameter(e.target.value)}
                    className="w-full bg-white/10 border border-white/20 rounded-xl py-2 pl-10 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500 placeholder:text-emerald-100/40"
                  />
                </div>
              </div>
              <button 
                type="submit"
                disabled={searchLoading}
                className="bg-emerald-500 hover:bg-emerald-400 disabled:bg-emerald-800 transition-all h-[38px] rounded-xl text-sm font-bold shadow-lg flex items-center justify-center gap-2"
              >
                {searchLoading ? <Loader2 className="animate-spin" size={18} /> : <>Find Trees <Sparkles size={16} /></>}
              </button>
            </form>

            {recommendations.length > 0 && (
              <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-4 animate-in fade-in slide-in-from-top-4 duration-500">
                {recommendations.map((rec, i) => (
                  <div key={i} className="bg-white/10 backdrop-blur-md rounded-2xl border border-white/10 overflow-hidden flex flex-col group hover:border-white/30 transition-all">
                    <div className="aspect-[4/3] bg-emerald-950 flex items-center justify-center relative overflow-hidden">
                      {rec.imageUrl ? (
                        <img src={rec.imageUrl} alt={rec.commonName} className="w-full h-full object-cover group-hover:scale-105 transition-all duration-700" />
                      ) : (
                        <ImageIcon size={32} className="text-emerald-800/50" />
                      )}
                      <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-emerald-950/80 to-transparent p-3">
                         <span className="text-[9px] font-black tracking-widest text-emerald-300 uppercase">Recommendation</span>
                      </div>
                    </div>
                    <div className="p-4 flex-1 flex flex-col justify-between">
                      <div>
                        <h4 className="font-bold text-emerald-50 leading-tight mb-0.5 line-clamp-1">{rec.commonName}</h4>
                        <p className="text-[10px] italic text-emerald-300 mb-3">{rec.botanicalName}</p>
                        <p className="text-[11px] text-emerald-100/70 line-clamp-2 mb-4 leading-relaxed">{rec.description}</p>
                      </div>
                      <div className="space-y-3">
                        <div className="flex justify-between items-center text-xs">
                           <span className="text-emerald-400 font-medium">Cover Range</span>
                           <span className="font-bold text-white">{rec.matureDiameterRange}</span>
                        </div>
                        <button 
                          onClick={() => {
                            const dia = parseFloat(rec.matureDiameterRange.split('-')[1]) || parseFloat(rec.matureDiameterRange) || 6;
                            addTree({ type: rec.botanicalName, diameter: dia });
                          }}
                          className="w-full bg-white text-emerald-900 hover:bg-emerald-50 py-2 rounded-xl text-[11px] font-bold transition-all shadow-sm flex items-center justify-center gap-2"
                        >
                          Add to Inventory
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
          <div className="absolute top-0 right-0 w-80 h-80 bg-emerald-500/10 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div>
              <h2 className="text-xl font-bold text-slate-800">Proposed Tree Inventory</h2>
              <p className="text-sm text-slate-500 italic">Manage tree dimensions and compliant canopy areas</p>
            </div>
            <button 
              onClick={() => addTree()}
              className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg transition-colors font-medium text-sm shadow-sm"
            >
              <Plus size={18} /> Manual Add
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Code</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Botanical Name</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Type</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Dia (m)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Required Area (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-emerald-600 uppercase tracking-widest">Compliant Cover (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-rose-600 uppercase tracking-widest text-right">Non Compliant</th>
                  <th className="px-6 py-4 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {sortedTrees.map((tree) => {
                  const classification = getClassification(tree.diameter);
                  const code = `${classification}${(++codeCounts[classification]).toString().padStart(2, '0')}`;
                  const requiredArea = calculateArea(tree.diameter);
                  const compliant = tree.compliantCover || 0;
                  const nonCompliant = Math.max(0, requiredArea - compliant);

                  const typeBadgeColor = classification === 'A' ? 'bg-indigo-50 text-indigo-700' : 
                                       classification === 'B' ? 'bg-emerald-50 text-emerald-700' : 
                                       'bg-amber-50 text-amber-700';

                  return (
                    <tr key={tree.id} className="hover:bg-slate-50 transition-colors group">
                      <td className="px-6 py-4">
                        <span className="font-mono text-[10px] font-bold text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded">
                          {code}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={tree.type}
                          onChange={(e) => updateTree(tree.id, { type: e.target.value })}
                          placeholder="e.g. Quercus rubra"
                          className="w-full bg-transparent border-b border-transparent hover:border-slate-200 focus:border-emerald-500 py-1 outline-none text-sm transition-all italic"
                        />
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className={`text-[11px] font-black px-2 py-0.5 rounded-full uppercase tracking-tighter ${typeBadgeColor}`}>
                          {classification}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <input 
                          type="number" 
                          step="0.1"
                          value={tree.diameter}
                          onChange={(e) => updateTree(tree.id, { diameter: Number(e.target.value) })}
                          className="w-16 px-2 py-1 rounded border border-slate-200 text-sm font-medium focus:ring-1 focus:ring-emerald-500 outline-none"
                        />
                      </td>
                      <td className="px-6 py-4 text-right text-xs text-slate-400 font-medium">
                        {requiredArea.toFixed(1)}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-1">
                          <input 
                            type="number" 
                            step="0.1"
                            value={tree.compliantCover ?? ''}
                            onChange={(e) => updateTree(tree.id, { compliantCover: Number(e.target.value) })}
                            className="w-24 px-2 py-1 rounded border border-emerald-200 focus:ring-1 focus:ring-emerald-500 outline-none text-sm font-bold bg-emerald-50/20"
                          />
                          <span className="text-[10px] text-emerald-500 font-bold">m²</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className={`text-xs font-bold ${nonCompliant > 0.1 ? 'text-rose-500' : 'text-slate-300'}`}>
                          {nonCompliant.toFixed(1)} m²
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => removeTree(tree.id)}
                          className="text-slate-200 hover:text-rose-500 transition-colors p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              {sortedTrees.length > 0 && (
                <tfoot className="bg-slate-50 font-bold text-slate-700 border-t border-slate-200">
                  <tr>
                    <td className="px-6 py-4" colSpan={4}>Inventory Totals</td>
                    <td className="px-6 py-4 text-right text-xs text-slate-400">{totalBioArea.toFixed(1)}</td>
                    <td className="px-6 py-4 text-emerald-700">{totalCompliantCover.toFixed(1)} m²</td>
                    <td className="px-6 py-4 text-right text-rose-500">{totalNonCompliant.toFixed(1)} m²</td>
                    <td></td>
                  </tr>
                </tfoot>
              )}
            </table>
          </div>
          <div className="p-4 bg-slate-50 border-t border-slate-100 text-[9px] font-bold uppercase text-slate-400 flex justify-center gap-6">
            <span className="flex items-center gap-1"><Info size={10} /> Type A: &lt;8m | Type B: 8-12m | Type C: &gt;12m</span>
            <span className="flex items-center gap-1"><Info size={10} /> REQUIRED AREA: BIOLOGICAL CANOPY (πr²)</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export interface TreeItem {
  id: string;
  qty: number;
  type: string;
  diameter: number;
  compliantCover?: number; // User input for actual compliant canopy area
}

export interface SoilEntry {
  id: string;
  areaId: string;
  treeIds: string[]; // References multiple TreeItem.ids
  soilAreaProvided: number;
  isCluster: boolean;
}

export interface AnalysisResponse {
  summary: string;
  recommendations: string[];
}

export interface ProjectData {
  version: string;
  timestamp: number;
  siteArea: number;
  targetPct: number;
  trees: TreeItem[];
  soilEntries: SoilEntry[];
}

import React, { useState, useEffect, useRef } from 'react';
import { CanopyCalculator } from './components/CanopyCalculator';
import { DeepSoilCalculator } from './components/DeepSoilCalculator';
import { Layout, TreePine, Shovel, BrainCircuit, Save, FolderOpen, Download, Upload, Check, AlertCircle } from 'lucide-react';
import { AIInsights } from './components/AIInsights';
import { TreeItem, SoilEntry, ProjectData } from './types';

const STORAGE_KEY = 'urban_canopy_project_data';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'canopy' | 'soil' | 'ai'>('canopy');
  const [siteArea, setSiteArea] = useState<number>(1363.93);
  const [targetPct, setTargetPct] = useState<number>(20);
  const [trees, setTrees] = useState<TreeItem[]>([
    { id: '1', qty: 1, type: 'Quercus robur', diameter: 4.5, compliantCover: 15.9 },
    { id: '2', qty: 1, type: 'Acer rubrum', diameter: 8.5, compliantCover: 56.7 },
    { id: '3', qty: 1, type: 'Platanus acerifolia', diameter: 12.5, compliantCover: 122.7 },
  ]);
  const [soilEntries, setSoilEntries] = useState<SoilEntry[]>([]);

  // Feedback states
  const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Auto-load on first mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const data: ProjectData = JSON.parse(saved);
        setSiteArea(data.siteArea);
        setTargetPct(data.targetPct);
        setTrees(data.trees);
        setSoilEntries(data.soilEntries);
        showStatus('success', 'Project loaded from browser storage');
      } catch (e) {
        console.error("Failed to load saved data", e);
      }
    }
  }, []);

  // Auto-target coverage logic based on site area
  useEffect(() => {
    const autoTarget = siteArea < 1000 ? 10 : 20;
    setTargetPct(autoTarget);
  }, [siteArea]);

  const showStatus = (type: 'success' | 'error', msg: string) => {
    setStatus({ type, msg });
    setTimeout(() => setStatus(null), 3000);
  };

  const saveToLocal = () => {
    const data: ProjectData = {
      version: '1.0',
      timestamp: Date.now(),
      siteArea,
      targetPct,
      trees,
      soilEntries
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    showStatus('success', 'Project saved to browser');
  };

  const downloadProject = () => {
    const data: ProjectData = {
      version: '1.0',
      timestamp: Date.now(),
      siteArea,
      targetPct,
      trees,
      soilEntries
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `canopy-project-${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
    showStatus('success', 'Project file downloaded');
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data: ProjectData = JSON.parse(e.target?.result as string);
        setSiteArea(data.siteArea);
        setTargetPct(data.targetPct);
        setTrees(data.trees);
        setSoilEntries(data.soilEntries);
        showStatus('success', 'Project imported successfully');
      } catch (err) {
        showStatus('error', 'Invalid project file');
      }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Status Toast */}
      {status && (
        <div className={`fixed top-24 right-6 z-[60] px-4 py-3 rounded-xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 duration-300 border ${
          status.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
        }`}>
          {status.type === 'success' ? <Check size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-bold">{status.msg}</span>
        </div>
      )}

      {/* Header */}
      <header className="bg-emerald-800 text-white p-6 shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-100 p-2 rounded-lg">
              <TreePine className="text-emerald-800 w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Urban Canopy & Soil Architect</h1>
              <p className="text-emerald-200 text-xs font-medium">Professional Compliance Tool</p>
            </div>
          </div>

          <div className="flex flex-col md:flex-row items-center gap-4">
            {/* Project Controls */}
            <div className="flex items-center gap-1 bg-emerald-900/40 p-1 rounded-xl border border-emerald-700/50">
              <button 
                onClick={saveToLocal}
                title="Save to Browser"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Save size={16} /> <span className="hidden lg:inline">Save</span>
              </button>
              <div className="w-px h-4 bg-emerald-700 mx-1"></div>
              <button 
                onClick={downloadProject}
                title="Download JSON"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Download size={16} /> <span className="hidden lg:inline">Export</span>
              </button>
              <button 
                onClick={() => fileInputRef.current?.click()}
                title="Upload JSON"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Upload size={16} /> <span className="hidden lg:inline">Import</span>
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                accept=".json" 
                className="hidden" 
              />
            </div>

            {/* Navigation */}
            <nav className="flex bg-emerald-950/60 rounded-full p-1 border border-emerald-700/50">
              <button 
                onClick={() => setActiveTab('canopy')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'canopy' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <Layout size={16} /> Canopy
              </button>
              <button 
                onClick={() => setActiveTab('soil')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'soil' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <Shovel size={16} /> Deep Soil
              </button>
              <button 
                onClick={() => setActiveTab('ai')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'ai' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <BrainCircuit size={16} /> AI Planning
              </button>
            </nav>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full p-6 pb-24">
        {activeTab === 'canopy' && (
          <CanopyCalculator 
            siteArea={siteArea} setSiteArea={setSiteArea}
            targetPct={targetPct} setTargetPct={setTargetPct}
            trees={trees} setTrees={setTrees}
          />
        )}
        {activeTab === 'soil' && (
          <DeepSoilCalculator 
            entries={soilEntries} setEntries={setSoilEntries}
            trees={trees}
          />
        )}
        {activeTab === 'ai' && (
          <AIInsights 
            siteArea={siteArea}
            targetPct={targetPct}
            trees={trees}
            soilEntries={soilEntries}
          />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-slate-100 border-t border-slate-200 py-8 text-center text-slate-500 text-xs font-medium uppercase tracking-widest">
        <p>&copy; {new Date().getFullYear()} Urban Planning Solutions. Professional Tools for Greener Cities.</p>
      </footer>
    </div>
  );
};

export default App;

export interface TreeItem {
  id: string;
  code?: string; // User editable code (e.g., A01, T1)
  qty: number;
  type: string;
  diameter: number;
  compliantCover?: number; // User input for actual compliant canopy area
}

export interface SoilEntry {
  id: string;
  areaId: string;
  treeIds: string[]; // References multiple TreeItem.ids
  soilAreaProvided: number;
  isCluster: boolean;
