import React, { useState, useEffect, useRef } from 'react';
import { CanopyCalculator } from './components/CanopyCalculator';
import { DeepSoilCalculator } from './components/DeepSoilCalculator';
import { Layout, TreePine, Shovel, BrainCircuit, Save, FolderOpen, Download, Upload, Check, AlertCircle } from 'lucide-react';
import { AIInsights } from './components/AIInsights';
import { TreeItem, SoilEntry, ProjectData } from './types';

const STORAGE_KEY = 'urban_canopy_project_data';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'canopy' | 'soil' | 'ai'>('canopy');
  const [siteArea, setSiteArea] = useState<number>(1363.93);
  const [targetPct, setTargetPct] = useState<number>(20);
  const [trees, setTrees] = useState<TreeItem[]>([
    { id: '1', code: 'A01', qty: 1, type: 'Quercus robur', diameter: 4.5, compliantCover: 15.9 },
    { id: '2', code: 'B01', qty: 1, type: 'Acer rubrum', diameter: 8.5, compliantCover: 56.7 },
    { id: '3', code: 'C01', qty: 1, type: 'Platanus acerifolia', diameter: 12.5, compliantCover: 122.7 },
  ]);
  const [soilEntries, setSoilEntries] = useState<SoilEntry[]>([]);

  // Feedback states
  const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Auto-load on first mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const data: ProjectData = JSON.parse(saved);
        setSiteArea(data.siteArea);
        setTargetPct(data.targetPct);
        setTrees(data.trees);
        setSoilEntries(data.soilEntries);
        showStatus('success', 'Project loaded from browser storage');
      } catch (e) {
        console.error("Failed to load saved data", e);
      }
    }
  }, []);

  // Auto-target coverage logic based on site area
  useEffect(() => {
    const autoTarget = siteArea < 1000 ? 10 : 20;
    setTargetPct(autoTarget);
  }, [siteArea]);

  const showStatus = (type: 'success' | 'error', msg: string) => {
    setStatus({ type, msg });
    setTimeout(() => setStatus(null), 3000);
  };

  const saveToLocal = () => {
    const data: ProjectData = {
      version: '1.0',
      timestamp: Date.now(),
      siteArea,
      targetPct,
      trees,
      soilEntries
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    showStatus('success', 'Project saved to browser');
  };

  const downloadProject = () => {
    const data: ProjectData = {
      version: '1.0',
      timestamp: Date.now(),
      siteArea,
      targetPct,
      trees,
      soilEntries
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `canopy-project-${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
    showStatus('success', 'Project file downloaded');
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data: ProjectData = JSON.parse(e.target?.result as string);
        setSiteArea(data.siteArea);
        setTargetPct(data.targetPct);
        setTrees(data.trees);
        setSoilEntries(data.soilEntries);
        showStatus('success', 'Project imported successfully');
      } catch (err) {
        showStatus('error', 'Invalid project file');
      }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Status Toast */}
      {status && (
        <div className={`fixed top-24 right-6 z-[60] px-4 py-3 rounded-xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 duration-300 border ${
          status.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
        }`}>
          {status.type === 'success' ? <Check size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-bold">{status.msg}</span>
        </div>
      )}

      {/* Header */}
      <header className="bg-emerald-800 text-white p-6 shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-100 p-2 rounded-lg">
              <TreePine className="text-emerald-800 w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Urban Canopy & Soil Architect</h1>
              <p className="text-emerald-200 text-xs font-medium">Professional Compliance Tool</p>
            </div>
          </div>

          <div className="flex flex-col md:flex-row items-center gap-4">
            {/* Project Controls */}
            <div className="flex items-center gap-1 bg-emerald-900/40 p-1 rounded-xl border border-emerald-700/50">
              <button 
                onClick={saveToLocal}
                title="Save to Browser"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Save size={16} /> <span className="hidden lg:inline">Save</span>
              </button>
              <div className="w-px h-4 bg-emerald-700 mx-1"></div>
              <button 
                onClick={downloadProject}
                title="Download JSON"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Download size={16} /> <span className="hidden lg:inline">Export</span>
              </button>
              <button 
                onClick={() => fileInputRef.current?.click()}
                title="Upload JSON"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Upload size={16} /> <span className="hidden lg:inline">Import</span>
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                accept=".json" 
                className="hidden" 
              />
            </div>

            {/* Navigation */}
            <nav className="flex bg-emerald-950/60 rounded-full p-1 border border-emerald-700/50">
              <button 
                onClick={() => setActiveTab('canopy')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'canopy' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <Layout size={16} /> Canopy
              </button>
              <button 
                onClick={() => setActiveTab('soil')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'soil' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <Shovel size={16} /> Deep Soil
              </button>
              <button 
                onClick={() => setActiveTab('ai')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'ai' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <BrainCircuit size={16} /> AI Planning
              </button>
            </nav>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full p-6 pb-24">
        {activeTab === 'canopy' && (
          <CanopyCalculator 
            siteArea={siteArea} setSiteArea={setSiteArea}
            targetPct={targetPct} setTargetPct={setTargetPct}
            trees={trees} setTrees={setTrees}
          />
        )}
        {activeTab === 'soil' && (
          <DeepSoilCalculator 
            entries={soilEntries} setEntries={setSoilEntries}
            trees={trees}
          />
        )}
        {activeTab === 'ai' && (
          <AIInsights 
            siteArea={siteArea}
            targetPct={targetPct}
            trees={trees}
            soilEntries={soilEntries}
          />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-slate-100 border-t border-slate-200 py-8 text-center text-slate-500 text-xs font-medium uppercase tracking-widest">
        <p>&copy; {new Date().getFullYear()} Urban Planning Solutions. Professional Tools for Greener Cities.</p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Plus, Trash2, TreePine, AlertCircle, CheckCircle2, Info } from 'lucide-react';
import { TreeItem } from '../types';

interface Props {
  siteArea: number;
  setSiteArea: (v: number) => void;
  targetPct: number;
  setTargetPct: (v: number) => void;
  trees: TreeItem[];
  setTrees: (v: TreeItem[]) => void;
}

export const CanopyCalculator: React.FC<Props> = ({ siteArea, setSiteArea, targetPct, setTargetPct, trees, setTrees }) => {
  const calculateArea = (dia: number) => Math.PI * Math.pow(dia / 2, 2);

  const getClassification = (d: number): 'A' | 'B' | 'C' => {
    if (d >= 12) return 'C';
    if (d >= 8) return 'B';
    return 'A';
  };

  const treeTypeCounts = {
    A: trees.filter(t => getClassification(t.diameter) === 'A').length,
    B: trees.filter(t => getClassification(t.diameter) === 'B').length,
    C: trees.filter(t => getClassification(t.diameter) === 'C').length,
  };

  const totalBioArea = trees.reduce((acc, t) => acc + calculateArea(t.diameter), 0);
  const totalCompliantCover = trees.reduce((acc, t) => acc + (t.compliantCover || 0), 0);
  const totalNonCompliant = Math.max(0, totalBioArea - totalCompliantCover);

  const minRequired = siteArea * (targetPct / 100);
  const diff = totalCompliantCover - minRequired;
  const currentPct = siteArea > 0 ? (totalCompliantCover / siteArea) * 100 : 0;

  const chartData = [
    { name: 'Compliant Canopy', value: totalCompliantCover, color: '#10b981' },
    { name: 'Remaining Site', value: Math.max(0, siteArea - totalCompliantCover), color: '#e2e8f0' }
  ];

  const addTree = () => {
    const id = Math.random().toString(36).substr(2, 9);
    const dia = 5.0;
    const classification = getClassification(dia);
    const count = trees.filter(t => getClassification(t.diameter) === classification).length + 1;
    const defaultCode = `${classification}${count.toString().padStart(2, '0')}`;
    const area = calculateArea(dia);

    setTrees([...trees, { 
      id, 
      code: defaultCode,
      qty: 1, 
      type: '', 
      diameter: dia, 
      compliantCover: Number(area.toFixed(1)) 
    }]);
  };

  const removeTree = (id: string) => {
    setTrees(trees.filter(t => t.id !== id));
  };

  const updateTree = (id: string, updates: Partial<TreeItem>) => {
    setTrees(trees.map(t => t.id === id ? { ...t, ...updates } : t));
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Configuration Panel */}
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-emerald-100 p-1.5 rounded-md"><TreePine size={18} className="text-emerald-600" /></div>
            Site Parameters
          </h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Total Site Area (m²)</label>
              <input 
                type="number" 
                value={siteArea}
                onChange={(e) => setSiteArea(Number(e.target.value))}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 transition-all outline-none"
              />
              <p className="text-[10px] text-slate-400 mt-1 font-semibold italic">
                {siteArea < 1000 ? "Target 10% applied (Area < 1000m²)" : "Target 20% applied (Area ≥ 1000m²)"}
              </p>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1 flex justify-between">
                Target Coverage <span>{targetPct}%</span>
              </label>
              <input 
                type="range" 
                min="0" max="100" 
                value={targetPct}
                onChange={(e) => setTargetPct(Number(e.target.value))}
                className="w-full accent-emerald-600 cursor-pointer"
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <div className="bg-blue-100 p-1.5 rounded-md"><CheckCircle2 size={18} className="text-blue-600" /></div>
            Site Metrics
          </h2>
          <div className="space-y-4">
            <div className="p-4 bg-slate-50 rounded-xl space-y-3">
              <div className="flex justify-between items-center border-b border-slate-200 pb-2">
                <span className="text-sm font-bold text-slate-600">Total Tree Number</span>
                <span className="text-lg font-black text-slate-800">{trees.length}</span>
              </div>
              <div className="grid grid-cols-3 gap-2 text-center pt-1">
                <div className="bg-white p-2 rounded-lg border border-slate-100 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">A</p>
                  <p className="text-sm font-black text-indigo-600">{treeTypeCounts.A}</p>
                </div>
                <div className="bg-white p-2 rounded-lg border border-slate-100 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">B</p>
                  <p className="text-sm font-black text-emerald-600">{treeTypeCounts.B}</p>
                </div>
                <div className="bg-white p-2 rounded-lg border border-slate-100 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">C</p>
                  <p className="text-sm font-black text-amber-600">{treeTypeCounts.C}</p>
                </div>
              </div>
            </div>

            <div className="flex justify-between items-center px-3 py-2 bg-slate-50 rounded-xl text-xs">
              <span className="font-medium text-slate-500">Min. Required</span>
              <span className="font-bold text-slate-800">{minRequired.toFixed(2)} m²</span>
            </div>
            <div className="flex justify-between items-center px-3 py-2 bg-slate-50 rounded-xl text-xs">
              <span className="font-medium text-slate-500">Compliant Total</span>
              <span className="font-bold text-emerald-600">{totalCompliantCover.toFixed(2)} m²</span>
            </div>

            <div className={`p-4 rounded-xl flex items-center gap-3 ${diff >= 0 ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-rose-50 text-rose-700 border border-rose-100'}`}>
              {diff >= 0 ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
              <div>
                <p className="font-bold text-sm">{diff >= 0 ? 'Compliance Met' : 'Shortfall'}</p>
                <p className="text-xs opacity-90">{Math.abs(diff).toFixed(2)} m² {diff >= 0 ? 'excess' : 'shortfall'}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-48 relative">
          <ResponsiveContainer width="100%" height="90%">
            <PieChart>
              <Pie
                data={chartData}
                innerRadius={50}
                outerRadius={70}
                paddingAngle={5}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none mt-4">
            <span className="text-xl font-bold text-slate-800">{currentPct.toFixed(1)}%</span>
            <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">Compliant</span>
          </div>
        </div>
      </div>

      {/* Tree Inventory Table */}
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div>
              <h2 className="text-xl font-bold text-slate-800">Proposed Tree Inventory</h2>
              <p className="text-sm text-slate-500 italic">Manage tree dimensions and compliant canopy areas</p>
            </div>
            <button 
              onClick={addTree}
              className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg transition-colors font-medium text-sm shadow-sm"
            >
              <Plus size={18} /> Add Tree
            </button>
          </div>
          <div className="w-full">
            <table className="w-full text-left table-fixed">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                  <th className="px-4 py-3 w-[70px]">Code</th>
                  <th className="px-4 py-3">Botanical Name</th>
                  <th className="px-4 py-3 w-[60px] text-center">Type</th>
                  <th className="px-4 py-3 w-[75px] text-center">Dia (m)</th>
                  <th className="px-4 py-3 w-[90px] text-right">Req. Area</th>
                  <th className="px-4 py-3 w-[110px] text-emerald-600 text-center">Compliant</th>
                  <th className="px-4 py-3 w-[80px] text-rose-600 text-right">Non-Comp</th>
                  <th className="px-4 py-3 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {trees.map((tree) => {
                  const classification = getClassification(tree.diameter);
                  const requiredArea = calculateArea(tree.diameter);
                  const compliant = tree.compliantCover || 0;
                  const nonCompliant = Math.max(0, requiredArea - compliant);

                  const typeBadgeColor = classification === 'A' ? 'bg-indigo-50 text-indigo-700' : 
                                       classification === 'B' ? 'bg-emerald-50 text-emerald-700' : 
                                       'bg-amber-50 text-amber-700';

                  return (
                    <tr key={tree.id} className="hover:bg-slate-50 transition-colors group">
                      <td className="px-2 py-3">
                        <input 
                          type="text" 
                          value={tree.code || ''}
                          onChange={(e) => updateTree(tree.id, { code: e.target.value })}
                          className="w-full bg-slate-100 border border-slate-200 rounded px-1.5 py-1 text-[10px] font-mono font-bold text-slate-700 focus:ring-1 focus:ring-emerald-500 outline-none uppercase"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="text" 
                          value={tree.type}
                          onChange={(e) => updateTree(tree.id, { type: e.target.value })}
                          placeholder="Quercus..."
                          className="w-full bg-transparent border-b border-transparent hover:border-slate-200 focus:border-emerald-500 py-1 outline-none text-xs transition-all italic"
                        />
                      </td>
                      <td className="px-4 py-3 text-center">
                        <span className={`text-[11px] font-black px-2 py-0.5 rounded-full uppercase tracking-tighter ${typeBadgeColor}`}>
                          {classification}
                        </span>
                      </td>
                      <td className="px-4 py-3 text-center">
                        <input 
                          type="number" 
                          step="0.1"
                          value={tree.diameter}
                          onChange={(e) => updateTree(tree.id, { diameter: Number(e.target.value) })}
                          className="w-12 px-1 py-1 rounded border border-slate-200 text-xs font-medium focus:ring-1 focus:ring-emerald-500 outline-none text-center"
                        />
                      </td>
                      <td className="px-4 py-3 text-right text-[10px] text-slate-400 font-medium">
                        {requiredArea.toFixed(1)}
                      </td>
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-1 justify-center">
                          <input 
                            type="number" 
                            step="0.1"
                            value={tree.compliantCover ?? ''}
                            onChange={(e) => updateTree(tree.id, { compliantCover: Number(e.target.value) })}
                            className="w-16 px-1.5 py-1 rounded border border-emerald-200 focus:ring-1 focus:ring-emerald-500 outline-none text-xs font-bold bg-emerald-50/20 text-center"
                          />
                          <span className="text-[10px] text-emerald-500 font-bold">m²</span>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-right">
                        <span className={`text-[10px] font-bold ${nonCompliant > 0.1 ? 'text-rose-500' : 'text-slate-300'}`}>
                          {nonCompliant.toFixed(1)}
                        </span>
                      </td>
                      <td className="px-2 py-3 text-right">
                        <button 
                          onClick={() => removeTree(tree.id)}
                          className="text-slate-200 hover:text-rose-500 transition-colors p-1"
                        >
                          <Trash2 size={14} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              {trees.length > 0 && (
                <tfoot className="bg-slate-50 font-bold text-slate-700 border-t border-slate-200 text-xs">
                  <tr>
                    <td className="px-4 py-3" colSpan={4}>Totals</td>
                    <td className="px-4 py-3 text-right text-[10px] text-slate-400">{totalBioArea.toFixed(1)}</td>
                    <td className="px-4 py-3 text-center text-emerald-700">{totalCompliantCover.toFixed(1)} m²</td>
                    <td className="px-4 py-3 text-right text-rose-500">{totalNonCompliant.toFixed(1)}</td>
                    <td></td>
                  </tr>
                </tfoot>
              )}
            </table>
          </div>
          <div className="p-4 bg-slate-50 border-t border-slate-100 text-[9px] font-bold uppercase text-slate-400 flex justify-center gap-6">
            <span className="flex items-center gap-1"><Info size={10} /> Type A: &lt;8m | Type B: 8-12m | Type C: &gt;12m</span>
            <span className="flex items-center gap-1"><Info size={10} /> REQUIRED AREA: BIOLOGICAL CANOPY (πr²)</span>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Plus, Trash2, Shovel, Info, CheckCircle2, XCircle, AlertCircle, X } from 'lucide-react';
import { SoilEntry, TreeItem } from '../types';

interface Props {
  entries: SoilEntry[];
  setEntries: (v: SoilEntry[]) => void;
  trees: TreeItem[];
}

export const DeepSoilCalculator: React.FC<Props> = ({ entries, setEntries, trees }) => {
  const addEntry = () => {
    const id = Math.random().toString(36).substr(2, 9);

    setEntries([...entries, { 
      id, 
      areaId: `Zone ${entries.length + 1}`, 
      treeIds: [], 
      soilAreaProvided: 25.0, 
      isCluster: false 
    }]);
  };

  const removeEntry = (id: string) => {
    setEntries(entries.filter(e => e.id !== id));
  };

  const updateEntry = (id: string, updates: Partial<SoilEntry>) => {
    setEntries(entries.map(e => e.id === id ? { ...e, ...updates } : e));
  };

  const addTreeToZone = (zoneId: string, treeId: string) => {
    if (!treeId) return;
    const entry = entries.find(e => e.id === zoneId);
    if (entry && !entry.treeIds.includes(treeId)) {
      updateEntry(zoneId, { treeIds: [...entry.treeIds, treeId] });
    }
  };

  const removeTreeFromZone = (zoneId: string, treeId: string) => {
    const entry = entries.find(e => e.id === zoneId);
    if (entry) {
      updateEntry(zoneId, { treeIds: entry.treeIds.filter(id => id !== treeId) });
    }
  };

  const getTableBData = (diameter: number) => {
    if (diameter < 4) return { req: 0, dim: 0, class: 'N/A' };
    if (diameter < 5) return { req: 12, dim: 2.5, class: 'A' };
    if (diameter < 6) return { req: 16, dim: 3.0, class: 'A' };
    if (diameter < 7) return { req: 25, dim: 3.5, class: 'A' };
    if (diameter < 8) return { req: 36, dim: 4.0, class: 'A' };
    if (diameter < 9) return { req: 49, dim: 4.5, class: 'B' };
    if (diameter < 10) return { req: 64, dim: 5.0, class: 'B' };
    if (diameter < 11) return { req: 81, dim: 5.5, class: 'B' };
    if (diameter < 12) return { req: 100, dim: 6.0, class: 'B' };
    if (diameter < 13) return { req: 121, dim: 6.5, class: 'C' };
    if (diameter < 14) return { req: 136, dim: 7.0, class: 'C' };
    return { req: 144, dim: 7.5, class: 'C' };
  };

  const totalSoilProvided = entries.reduce((acc, curr) => acc + curr.soilAreaProvided, 0);

  return (
    <div className="space-y-6">
      {/* Informational Header */}
      <div className="bg-emerald-900 text-white p-8 rounded-3xl relative overflow-hidden shadow-xl">
        <div className="relative z-10">
          <h2 className="text-2xl font-bold mb-2 flex items-center gap-2">
            <Shovel size={28} /> Deep Soil Volume Assessment
          </h2>
          <p className="text-emerald-100/80 max-w-2xl mb-6">
            Ensuring adequate root volume is critical for tree health. Minimum soil area and dimension standards apply based on tree mature size.
          </p>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3 max-w-3xl">
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Small (Type A)</p>
                <p className="text-sm font-medium">Min Dim: 2.5m - 4.0m</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Medium (Type B)</p>
                <p className="text-sm font-medium">Min Dim: 4.5m - 6.0m</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10">
                <p className="text-[10px] font-bold text-emerald-300 uppercase tracking-widest mb-1">Large (Type C)</p>
                <p className="text-sm font-medium">Min Dim: 6.5m - 7.5m</p>
            </div>
          </div>
        </div>
        <div className="absolute top-0 right-0 w-80 h-80 bg-emerald-500/10 rounded-full -translate-y-1/3 translate-x-1/3 blur-3xl"></div>
      </div>

      {/* Calculator Table */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Soil Allocation Log</h3>
            <p className="text-sm text-slate-500 italic">Assign trees from inventory to deep soil zones</p>
          </div>
          <button 
            onClick={addEntry}
            disabled={trees.length === 0}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl transition-all font-bold text-sm shadow-sm ${ trees.length === 0 ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200' : 'bg-emerald-600 hover:bg-emerald-700 text-white'}`}
          >
            <Plus size={18} /> Add Soil Zone
          </button>
        </div>

        {trees.length === 0 ? (
          <div className="p-12 text-center space-y-4">
            <div className="bg-rose-50 text-rose-500 p-4 rounded-full w-16 h-16 flex items-center justify-center mx-auto">
                <AlertCircle size={32} />
            </div>
            <div className="max-w-xs mx-auto">
                <p className="font-bold text-slate-800">No Trees Detected</p>
                <p className="text-sm text-slate-500">Please add trees in the Canopy tab first.</p>
            </div>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-200">
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Zone ID</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">Linked Trees</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Provided Soil (m²)</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Cluster?</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Agg. Target</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-right">Req. Min Dim</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Status</th>
                  <th className="px-6 py-4 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {entries.map((entry) => {
                  const linkedTrees = trees.filter(t => entry.treeIds.includes(t.id));
                  const tableDataArray = linkedTrees.map(t => getTableBData(t.diameter));
                  const totalBaseReq = tableDataArray.reduce((sum, d) => sum + d.req, 0);
                  const maxRequiredDim = tableDataArray.length > 0 ? Math.max(...tableDataArray.map(d => d.dim)) : 0;
                  const adjustedReq = totalBaseReq * (entry.isCluster ? 0.95 : 1.0);
                  const isPass = entry.soilAreaProvided >= adjustedReq;

                  return (
                    <tr key={entry.id} className={`hover:bg-emerald-50/30 transition-colors group ${!isPass ? 'bg-rose-50/20' : ''}`}>
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={entry.areaId}
                          onChange={(e) => updateEntry(entry.id, { areaId: e.target.value })}
                          className="w-full bg-transparent border-b border-transparent focus:border-emerald-500 outline-none text-sm font-bold text-slate-700"
                        />
                      </td>
                      <td className="px-6 py-4 max-w-xs">
                        <div className="flex flex-wrap gap-1.5 mb-2">
                          {linkedTrees.map(t => (
                            <span key={t.id} className="inline-flex items-center gap-1 bg-white text-slate-700 px-2 py-1 rounded text-[10px] font-bold shadow-sm border border-slate-100 group/tag">
                              {t.code || '??'}
                              <button onClick={() => removeTreeFromZone(entry.id, t.id)} className="text-slate-400 hover:text-rose-500 transition-colors"><X size={12}/></button>
                            </span>
                          ))}
                        </div>
                        <select 
                          value=""
                          onChange={(e) => addTreeToZone(entry.id, e.target.value)}
                          className="w-full px-2 py-1 rounded bg-slate-50 border border-slate-200 text-[10px] font-medium focus:ring-1 focus:ring-emerald-500 outline-none"
                        >
                          <option value="">+ Add tree...</option>
                          {trees.map(t => (
                            <option key={t.id} value={t.id} disabled={entry.treeIds.includes(t.id)}>
                              {t.code || '??'} &mdash; {t.type || 'Unnamed'} ({t.diameter}m)
                            </option>
                          ))}
                        </select>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex items-center justify-end gap-2">
                            {!isPass && <AlertCircle size={14} className="text-rose-500 animate-pulse" />}
                            <div className="flex items-center gap-1">
                                <input 
                                    type="number" 
                                    value={entry.soilAreaProvided}
                                    onChange={(e) => updateEntry(entry.id, { soilAreaProvided: Number(e.target.value) })}
                                    className={`w-20 px-2 py-1.5 rounded border text-sm font-bold text-right transition-all outline-none ${
                                      isPass 
                                      ? 'border-slate-200 focus:border-emerald-500' 
                                      : 'border-rose-300 bg-rose-50 text-rose-700 focus:ring-1 focus:ring-rose-500'
                                    }`}
                                />
                                <span className="text-xs text-slate-400 font-medium">m²</span>
                            </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <input 
                          type="checkbox" 
                          checked={entry.isCluster}
                          onChange={(e) => updateEntry(entry.id, { isCluster: e.target.checked })}
                          className="w-4 h-4 accent-emerald-600 rounded cursor-pointer"
                        />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex flex-col">
                            <span className="text-sm font-bold text-slate-800">{adjustedReq.toFixed(1)}m²</span>
                            {entry.isCluster && entry.treeIds.length > 0 && <span className="text-[9px] text-emerald-600 font-bold uppercase">-5% Cluster</span>}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="text-sm font-mono font-bold text-slate-600">
                          {maxRequiredDim > 0 ? `${maxRequiredDim.toFixed(1)}m` : '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-[10px] font-bold border transition-all ${isPass ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-rose-100 text-rose-700 border-rose-200'}`}>
                          {isPass ? <CheckCircle2 size={12} /> : <XCircle size={12} />}
                          {isPass ? 'Pass' : 'Shortfall'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button onClick={() => removeEntry(entry.id)} className="text-slate-300 hover:text-rose-500 transition-colors p-1"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              {entries.length > 0 && (
                <tfoot className="bg-slate-50 font-bold text-slate-700 border-t border-slate-200">
                  <tr>
                    <td className="px-6 py-4" colSpan={2}>Deep Soil Allocation Totals</td>
                    <td className="px-6 py-4 text-right">
                        <div className="flex flex-col items-end">
                            <span className="text-emerald-700 text-sm">{totalSoilProvided.toFixed(1)} m²</span>
                            <span className="text-[9px] text-slate-400 uppercase tracking-tighter">Total Provided</span>
                        </div>
                    </td>
                    <td className="px-6 py-4" colSpan={5}></td>
                  </tr>
                </tfoot>
              )}
            </table>
          </div>
        )}
        <div className="p-4 bg-slate-50/50 border-t border-slate-100 flex items-center justify-center gap-6">
            <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                <div className="w-3 h-3 bg-emerald-500 rounded-sm"></div> Compliant
            </div>
            <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                <div className="w-3 h-3 bg-rose-400 rounded-sm"></div> Area Shortfall
            </div>
            <div className="flex items-center gap-1 text-[10px] text-slate-400 font-medium italic">
                <Info size={12} className="text-emerald-500" /> Req. Min Dim is the largest minimum dimension requirement among all linked trees.
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { CanopyCalculator } from './components/CanopyCalculator';
import { DeepSoilCalculator } from './components/DeepSoilCalculator';
import { Layout, TreePine, Shovel, BrainCircuit, Save, FolderOpen, Download, Upload, Check, AlertCircle, Image as ImageIcon, Camera } from 'lucide-react';
import { AIInsights } from './components/AIInsights';
import { TreeItem, SoilEntry, ProjectData } from './types';
import { toPng } from 'html-to-image';

const STORAGE_KEY = 'urban_canopy_project_data';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'canopy' | 'soil' | 'ai'>('canopy');
  const [siteArea, setSiteArea] = useState<number>(1363.93);
  const [targetPct, setTargetPct] = useState<number>(20);
  const [trees, setTrees] = useState<TreeItem[]>([
    { id: '1', code: 'A01', qty: 1, type: 'Quercus robur', diameter: 4.5, compliantCover: 15.9 },
    { id: '2', code: 'B01', qty: 1, type: 'Acer rubrum', diameter: 8.5, compliantCover: 56.7 },
    { id: '3', code: 'C01', code: 'C01', qty: 1, type: 'Platanus acerifolia', diameter: 12.5, compliantCover: 122.7 },
  ]);
  const [soilEntries, setSoilEntries] = useState<SoilEntry[]>([]);

  // Feedback states
  const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const contentRef = useRef<HTMLElement>(null);

  // Auto-load on first mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const data: ProjectData = JSON.parse(saved);
        setSiteArea(data.siteArea);
        setTargetPct(data.targetPct);
        setTrees(data.trees);
        setSoilEntries(data.soilEntries);
        showStatus('success', 'Project loaded from browser storage');
      } catch (e) {
        console.error("Failed to load saved data", e);
      }
    }
  }, []);

  // Auto-target coverage logic based on site area
  useEffect(() => {
    const autoTarget = siteArea < 1000 ? 10 : 20;
    setTargetPct(autoTarget);
  }, [siteArea]);

  const showStatus = (type: 'success' | 'error', msg: string) => {
    setStatus({ type, msg });
    setTimeout(() => setStatus(null), 3000);
  };

  const saveToLocal = () => {
    const data: ProjectData = {
      version: '1.0',
      timestamp: Date.now(),
      siteArea,
      targetPct,
      trees,
      soilEntries
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    showStatus('success', 'Project saved to browser');
  };

  const downloadProject = () => {
    const data: ProjectData = {
      version: '1.0',
      timestamp: Date.now(),
      siteArea,
      targetPct,
      trees,
      soilEntries
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `canopy-project-${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
    showStatus('success', 'Project file downloaded');
  };

  const exportAsImage = async () => {
    if (!contentRef.current) return;

    showStatus('success', 'Preparing image export...');
    try {
      const dataUrl = await toPng(contentRef.current, {
        cacheBust: true,
        backgroundColor: '#f8fafc', // Same as bg-slate-50
        style: {
          padding: '20px',
        }
      });
      const link = document.createElement('a');
      link.download = `canopy-snapshot-${new Date().toISOString().split('T')[0]}.png`;
      link.href = dataUrl;
      link.click();
      showStatus('success', 'Image exported successfully');
    } catch (err) {
      console.error('oops, something went wrong!', err);
      showStatus('error', 'Failed to export image');
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data: ProjectData = JSON.parse(e.target?.result as string);
        setSiteArea(data.siteArea);
        setTargetPct(data.targetPct);
        setTrees(data.trees);
        setSoilEntries(data.soilEntries);
        showStatus('success', 'Project imported successfully');
      } catch (err) {
        showStatus('error', 'Invalid project file');
      }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Status Toast */}
      {status && (
        <div className={`fixed top-24 right-6 z-[60] px-4 py-3 rounded-xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 duration-300 border ${
          status.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
        }`}>
          {status.type === 'success' ? <Check size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-bold">{status.msg}</span>
        </div>
      )}

      {/* Header */}
      <header className="bg-emerald-800 text-white p-6 shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-100 p-2 rounded-lg">
              <TreePine className="text-emerald-800 w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Urban Canopy & Soil Architect</h1>
              <p className="text-emerald-200 text-xs font-medium">Professional Compliance Tool</p>
            </div>
          </div>

          <div className="flex flex-col md:flex-row items-center gap-4">
            {/* Project Controls */}
            <div className="flex items-center gap-1 bg-emerald-900/40 p-1 rounded-xl border border-emerald-700/50">
              <button 
                onClick={saveToLocal}
                title="Save to Browser"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Save size={16} /> <span className="hidden lg:inline">Save</span>
              </button>
              <div className="w-px h-4 bg-emerald-700 mx-1"></div>
              <button 
                onClick={downloadProject}
                title="Download JSON"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Download size={16} /> <span className="hidden lg:inline">Export JSON</span>
              </button>
              <button 
                onClick={exportAsImage}
                title="Save as Image"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Camera size={16} /> <span className="hidden lg:inline">Snapshot</span>
              </button>
              <div className="w-px h-4 bg-emerald-700 mx-1"></div>
              <button 
                onClick={() => fileInputRef.current?.click()}
                title="Upload JSON"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Upload size={16} /> <span className="hidden lg:inline">Import</span>
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                accept=".json" 
                className="hidden" 
              />
            </div>

            {/* Navigation */}
            <nav className="flex bg-emerald-950/60 rounded-full p-1 border border-emerald-700/50">
              <button 
                onClick={() => setActiveTab('canopy')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'canopy' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <Layout size={16} /> Canopy
              </button>
              <button 
                onClick={() => setActiveTab('soil')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'soil' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <Shovel size={16} /> Deep Soil
              </button>
              <button 
                onClick={() => setActiveTab('ai')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'ai' ? 'bg-emerald-500 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <BrainCircuit size={16} /> AI Planning
              </button>
            </nav>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main ref={contentRef} className="flex-1 max-w-7xl mx-auto w-full p-6 pb-24">
        {activeTab === 'canopy' && (
          <CanopyCalculator 
            siteArea={siteArea} setSiteArea={setSiteArea}
            targetPct={targetPct} setTargetPct={setTargetPct}
            trees={trees} setTrees={setTrees}
          />
        )}
        {activeTab === 'soil' && (
          <DeepSoilCalculator 
            entries={soilEntries} setEntries={setSoilEntries}
            trees={trees}
          />
        )}
        {activeTab === 'ai' && (
          <AIInsights 
            siteArea={siteArea}
            targetPct={targetPct}
            trees={trees}
            soilEntries={soilEntries}
          />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-slate-100 border-t border-slate-200 py-8 text-center text-slate-500 text-xs font-medium uppercase tracking-widest">
        <p>&copy; {new Date().getFullYear()} Urban Planning Solutions. Professional Tools for Greener Cities.</p>
      </footer>
    </div>
  );
};

export default App;

