        setTrees(data.trees);
        setSoilEntries(data.soilEntries);
        showStatus('success', 'Project loaded from browser storage');
      } catch (e) {
        console.error("Failed to load saved data", e);
      }
    }
  }, []);

  // Auto-target coverage logic based on site area
  useEffect(() => {
    const autoTarget = siteArea < 1000 ? 10 : 20;
    setTargetPct(autoTarget);
  }, [siteArea]);

  const showStatus = (type: 'success' | 'error', msg: string) => {
    setStatus({ type, msg });
    setTimeout(() => setStatus(null), 3000);
  };

  const saveToLocal = () => {
    const data: ProjectData = {
      version: '1.0',
      timestamp: Date.now(),
      siteArea,
      targetPct,
      trees,
      soilEntries
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    showStatus('success', 'Project saved to browser');
  };

  const downloadProject = () => {
    const data: ProjectData = {
      version: '1.0',
      timestamp: Date.now(),
      siteArea,
      targetPct,
      trees,
      soilEntries
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `canopy-project-${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
    showStatus('success', 'Project file downloaded');
  };

  const exportAsImage = async () => {
    if (!contentRef.current) return;

    showStatus('success', 'Preparing image export...');
    try {
      const dataUrl = await toPng(contentRef.current, {
        cacheBust: true,
        backgroundColor: '#f8fafc', // Same as bg-slate-50
        style: {
          padding: '20px',
        }
      });
      const link = document.createElement('a');
      link.download = `canopy-snapshot-${new Date().toISOString().split('T')[0]}.png`;
      link.href = dataUrl;
      link.click();
      showStatus('success', 'Image exported successfully');
    } catch (err) {
      console.error('oops, something went wrong!', err);
      showStatus('error', 'Failed to export image');
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data: ProjectData = JSON.parse(e.target?.result as string);
        setSiteArea(data.siteArea);
        setTargetPct(data.targetPct);
        setTrees(data.trees);
        setSoilEntries(data.soilEntries);
        showStatus('success', 'Project imported successfully');
      } catch (err) {
        showStatus('error', 'Invalid project file');
      }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Status Toast */}
      {status && (
        <div className={`fixed top-24 right-6 z-[60] px-4 py-3 rounded-xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 duration-300 border ${
          status.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
        }`}>
          {status.type === 'success' ? <Check size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-bold">{status.msg}</span>
        </div>
      )}

      {/* Header */}
      <header className="bg-emerald-800 text-white p-6 shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-100 p-2 rounded-lg">
              <TreePine className="text-emerald-800 w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Urban Canopy & Soil Architect</h1>
              <p className="text-emerald-200 text-xs font-medium">Professional Compliance Tool</p>
            </div>
          </div>

          <div className="flex flex-col md:flex-row items-center gap-4">
            {/* Project Controls */}
            <div className="flex items-center gap-1 bg-emerald-900/40 p-1 rounded-xl border border-emerald-700/50">
              <button 
                onClick={saveToLocal}
                title="Save to Browser"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Save size={16} /> <span className="hidden lg:inline">Save</span>
              </button>
              <div className="w-px h-4 bg-emerald-700 mx-1"></div>
              <button 
                onClick={downloadProject}
                title="Download JSON"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Download size={16} /> <span className="hidden lg:inline">Export JSON</span>
              </button>
              <button 
                onClick={exportAsImage}
                title="Save as Image"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Camera size={16} /> <span className="hidden lg:inline">Snapshot</span>
              </button>
              <div className="w-px h-4 bg-emerald-700 mx-1"></div>
              <button 
                onClick={() => fileInputRef.current?.click()}
                title="Upload JSON"
                className="p-2 hover:bg-emerald-700/50 rounded-lg transition-colors text-emerald-100 flex items-center gap-2 text-xs font-bold"
              >
                <Upload size={16} /> <span className="hidden lg:inline">Import</span>
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                accept=".json" 
                className="hidden" 
              />
            </div>

            {/* Navigation */}
            <nav className="flex bg-emerald-950/60 rounded-full p-1 border border-emerald-700/50">
              <button 
                onClick={() => setActiveTab('canopy')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'canopy' ? 'bg-emerald-50 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <Layout size={16} /> Canopy
              </button>
              <button 
                onClick={() => setActiveTab('soil')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'soil' ? 'bg-emerald-50 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <Shovel size={16} /> Deep Soil
              </button>
              <button 
                onClick={() => setActiveTab('ai')}
                className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-sm font-bold ${activeTab === 'ai' ? 'bg-emerald-50 text-white shadow-lg' : 'hover:bg-emerald-800/50 text-emerald-200/70'}`}
              >
                <BrainCircuit size={16} /> AI Planning
              </button>
            </nav>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main ref={contentRef} className="flex-1 max-w-7xl mx-auto w-full p-6 pb-24">
        {activeTab === 'canopy' && (
          <CanopyCalculator 
            siteArea={siteArea} setSiteArea={setSiteArea}
            targetPct={targetPct} setTargetPct={setTargetPct}
            trees={trees} setTrees={setTrees}
          />
        )}
        {activeTab === 'soil' && (
          <DeepSoilCalculator 
            entries={soilEntries} setEntries={setSoilEntries}
            trees={trees}
          />
        )}
        {activeTab === 'ai' && (
          <AIInsights 
            siteArea={siteArea}
            targetPct={targetPct}
            trees={trees}
            soilEntries={soilEntries}
          />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-slate-100 border-t border-slate-200 py-8 text-center text-slate-500 text-xs font-medium uppercase tracking-widest">
        <p>&copy; {new Date().getFullYear()} Urban Planning Solutions. Professional Tools for Greener Cities.</p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { TreeItem, SoilEntry } from "../types";

export interface TreeRecommendation {
  botanicalName: string;
  commonName: string;
  matureDiameterRange: string;
  description: string;
  imageUrl?: string;
  sourceUrl?: string;
}

export const getAIPlanningInsights = async (
  siteArea: number,
  targetPct: number,
  trees: TreeItem[],
  soilEntries: SoilEntry[]
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    As an Urban Landscape Architect, analyze this site:
    Total Site Area: ${siteArea} m2
    Target Canopy Percentage: ${targetPct}%
    Current Trees: ${JSON.stringify(trees)}
    Soil Provisions: ${JSON.stringify(soilEntries)}

    Provide a concise professional summary and 3-4 actionable recommendations to improve canopy health or meet urban planning targets.
  `;

  // Fix: Using gemini-3-pro-preview for complex reasoning tasks
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          recommendations: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "recommendations"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const getTreeRecommendationsByCriteria = async (postcode: string, minDiameter: number): Promise<{ recommendations: TreeRecommendation[], sources: any[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Using information from 'Which Plant Where' (whichplantwhere.com.au), search for 3 tree species suitable for urban planting in Australia postcode ${postcode}.
    Each tree must have a mature canopy spread of at least ${minDiameter}m.
    Return the data in a JSON array. 
    Include: botanicalName, commonName, matureDiameterRange (e.g. "5-8m"), and a brief description.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

  // Extract JSON from text response safely; search grounding output text might not be pure JSON.
  const text = response.text || "";
  const jsonStart = text.indexOf('[');
  const jsonEnd = text.lastIndexOf(']') + 1;

  if (jsonStart !== -1 && jsonEnd > jsonStart) {
    const jsonStr = text.substring(jsonStart, jsonEnd);
    try {
      return { recommendations: JSON.parse(jsonStr), sources };
    } catch (e) {
      console.error("JSON Parse Error", e);
    }
  }

  return { recommendations: [], sources };
};

export const generateTreeImage = async (treeName: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A photorealistic render of a mature ${treeName} tree in an urban garden, high quality architectural visualization.` }]
      }
    });

    // Fix: Iterating through parts to find the image part instead of assuming first part is image
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const base64EncodeString: string = part.inlineData.data;
          return `data:image/png;base64,${base64EncodeString}`;
        }
      }
    }
  } catch (e) {
    console.error("Image Gen Error", e);
  }
  return null;
};
